window.__LIBQ=window.__LIBQ||{};window.__LIBQ["the-gioi-hoan-my"]=window.__LIBQ["the-gioi-hoan-my"]||{};window.__LIBQ["the-gioi-hoan-my"]["q02"]=window.__LIBQ["the-gioi-hoan-my"]["q02"]||{};window.__LIBQ["the-gioi-hoan-my"]["q02"]["artifacts"]={"updatedAt":"2026-07-04","count":138,"artifacts":[{"id":"bach-cot-dai-bong","name":"Bạch cốt đại bổng","aliases":["Búa (của nhóc tỳ)"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Cây gậy lớn bằng xương trắng của Nhóc tỳ, dùng như búa để tập kích.","detail":"Bạch cốt đại bổng là cây gậy lớn bằng xương trắng của Nhóc tỳ (Thạch Hạo), dùng giống như một cây búa để tập kích bất ngờ. Trong đòn đánh lén cuối chương, Nhóc tỳ từ cây gỗ khô sau lưng Tiêu Thiên nứt ra, giáng hai búa liên tiếp vào sau gáy, quật ngã kẻ mạnh nhất hơn chín vạn người — trở thành đòn tủ hạ gục cường giả của lối đánh du kích ẩn thân.","nguon":["@c0101"]},{"id":"bo-thien-thach","name":"Bổ Thiên thạch","aliases":[],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Tiêu Thiên"],"trangThai":"dang-co","blurb":"Vật phẩm nhiệm vụ mà thí sinh phải cướp đoạt để đạt yêu cầu vượt qua đợt kiểm tra của Bổ Thiên các.","detail":"Bổ Thiên thạch là thứ thí sinh phải cướp đoạt để đạt yêu cầu thấp nhất vượt qua đợt kiểm tra tại chiến trường thứ hai. Kẻ bại trận bị cướp sạch, còn Tiêu Thiên một đêm chinh chiến thu được 16 khối. Nhóc tỳ cũng quay lại chiến trường tan hoang để đoạt thêm.","nguon":["@c0101"]},{"id":"bao-dan-tieu-thien","name":"Bảo đan","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Tiêu Thiên"],"trangThai":"da-dung","blurb":"Đan dược hồi phục Tiêu Thiên nuốt để khôi phục trạng thái cường thịnh sau ác chiến.","detail":"Viên bảo đan Tiêu Thiên nuốt sau đại chiến khiến toàn thân sáng lên, khôi phục về trạng thái cường thịnh nhanh chóng.","nguon":["@c0101"]},{"id":"bao-dan-bo-tinh-tri-thuong","name":"Bảo đan (bổ tinh huyết & trị trọng thương)","category":"dan-duoc","categoryLabel":"Đan dược","soHuu":["Tiêu Thiên","Thạch Hạo"],"trangThai":"dang-co","blurb":"Hai bình bảo đan quý giá, một loại bổ sung tinh huyết, một loại trị liệu trọng thương.","detail":"Hai bình bảo đan Tiêu Thiên mang theo: một loại bổ sung tinh huyết, một loại trị liệu trọng thương, rất có giá trị. Nhóc tỳ lấy được từ người Tiêu Thiên khi lục soát.","nguon":["@c0102"]},{"id":"de-tu","name":"Đế tử","category":"khac","categoryLabel":"Vật phẩm","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Một Đế tử nhỏ như sợi tóc, được mô tả là rất đáng tiền.","detail":"Một vật nhỏ như sợi tóc, rất đáng giá, trước đó khi tìm bảo vật đã bị bỏ sót, nay được Nhóc tỳ tiện tay thu lại.","nguon":["@c0102"]},{"id":"long-tan","name":"Long Tán","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":["Nhóc tỳ"],"trangThai":"Đã tặng cho hai huynh muội","blurb":"Một viên đan cường gân tráng cốt, khôi phục nguyên khí trong nháy mắt.","detail":"Đan dược quý cường gân tráng cốt, giúp khôi phục nguyên khí trong nháy mắt. Vốn là chiến lợi phẩm nhóc tỳ lột được từ thiếu niên áo bạc (Tiêu Thiên); trước khi chia tay, nhóc tỳ tặng mỗi người trong hai huynh muội một viên rút ra từ hai bình thuốc quý cùng với Hổ Dược.","nguon":["@c0103"]},{"id":"ho-duoc","name":"Hổ Dược","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":["Nhóc tỳ"],"trangThai":"Đã tặng cho hai huynh muội","blurb":"Đan dược trị thương công hiệu thần kỳ, rất quý.","detail":"Đan dược quý dùng để trị thương, công hiệu thần kỳ. Cũng là chiến lợi phẩm nhóc tỳ lột được từ thiếu niên áo bạc (Tiêu Thiên); được tặng cho hai huynh muội cùng với Long Tán từ hai bình thuốc quý.","nguon":["@c0103"]},{"id":"bua-cua-nhoc-ty","name":"Búa của nhóc tỳ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nhóc tỳ"],"trangThai":"Đang sử dụng","blurb":"Vũ khí búa nhóc tỳ dùng đánh lén, từng gõ ngất Tiêu Thiên hai búa vào cùng một chỗ.","detail":"Vũ khí búa của nhóc tỳ, dùng để đánh lén khiến thiếu niên áo bạc (Tiêu Thiên) ngất cả đêm; hai phát búa trúng cùng một chỗ trên trán Tiêu Thiên khiến hắn mọc một cục u to như sừng. Nhóc tỳ tự gắn danh hiệu với vũ khí này qua câu khắc trên đá “Búa ở trong tay, thiên hạ ta có”.","nguon":["@c0103"]},{"id":"hac-ho-sat","name":"Hắc Hổ Sát","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Bổ Thiên Các"],"trangThai":"Được dùng chăm bón gốc thuốc quý","blurb":"Chất bồi dưỡng quý dùng chăm bón gốc thuốc của Bổ Thiên Các.","detail":"Chất bồi dưỡng quý được Bổ Thiên Các dùng để chăm bón một gốc thuốc quý; nhờ nuôi bằng Hắc Hổ Sát, gốc thuốc ấy tương lai có thể lột xác thành Thánh Dược. Trác Vân trưởng lão mời khách “xem lễ” thưởng thức để phô nội tình tông môn, oai chấn tứ phương.","nguon":["@c0103"]},{"id":"goc-thuoc-thanh-duoc","name":"Gốc thuốc quý (tiềm năng Thánh Dược)","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":["Bổ Thiên Các"],"trangThai":"Đang được nuôi dưỡng","blurb":"Bảo vật của Bổ Thiên Các, nuôi bằng Hắc Hổ Sát, tương lai có thể lột xác thành Thánh Dược.","detail":"Một gốc thuốc quý được Bổ Thiên Các chăm bón bằng Hắc Hổ Sát; tương lai có tiềm năng lột xác thành Thánh Dược. Trác Vân trưởng lão đem ra mời khách thưởng thức nhằm phô nội tình tông môn.","nguon":["@c0103"]},{"id":"bao-cot-bo-thien-cac","name":"Bảo cốt","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Mười tám bộ bảo cốt sáng óng ánh nhóc tỳ giấu ở chiến trường thứ hai.","detail":"Mười tám bộ bảo cốt sáng óng ánh mà nhóc tỳ giấu ở chiến trường thứ hai; Bổ Thiên các chỉ tìm được sáu bộ (ba bộ trong tổ chim con, ba bộ sau thác nước), còn mười hai bộ chưa bị phát hiện.","nguon":["@c0105"]},{"id":"da-thu-co-phu-van","name":"Da thú cổ lấp lánh phù văn","category":"phap-bao","categoryLabel":"Pháp bảo vận chuyển","soHuu":["Bổ Thiên các"],"trangThai":"dang-co","blurb":"Tấm da thú cổ có phù văn, bay cách mặt đất hơn một mét, dùng chở cường giả và bảo vật.","detail":"Bay tới sơn môn Bổ Thiên các mang theo cường giả cùng tảng đá Tế Linh có chữ khiêu khích của Nhóc siêu quậy trong nghi thức nhập môn.","nguon":["@c0106"]},{"id":"xich-giao-dang","name":"Xích Giao đằng","category":"nguyen-lieu","categoryLabel":"Linh dược","blurb":"Linh dược dạng dây dài hơn hai mét trong Thượng cổ Tịnh Thổ.","detail":"Loại linh dược dạng dây leo dài mà Thạch Hạo nhòm ngó muốn chặt một khúc khi vừa vào sơn môn Bổ Thiên các.","nguon":["@c0106"]},{"id":"hoa-linh-tuoc","name":"Hỏa Linh tước","category":"khac","categoryLabel":"Linh cầm","blurb":"Bầy chim linh béo mập trong Thượng cổ Tịnh Thổ.","detail":"Loài linh cầm béo mập bay lượn trong sơn môn Bổ Thiên các mà Thạch Hạo thèm ăn ngay khi vừa nhập môn.","nguon":["@c0106"]},{"id":"duoc-tan","name":"Dược Tán","category":"dan-duoc","categoryLabel":"Đan dược","soHuu":[],"blurb":"Đan dược quý hiếm thiên tài doanh phát đầu tháng, giúp tu vi tăng nhanh.","detail":"Đầu mỗi tháng thiên tài doanh Bổ Thiên các phát Dược Tán cho đệ tử ưu tú; chính là mục tiêu Thanh Phong quyết cắn răng kiên trì để nhận được.","nguon":["@c0107","@c0113"]},{"id":"ho-lo-vo-vang-bo-thien-cac","name":"Hồ lô vỏ vàng","cn":"","aliases":["Chí bảo Bổ Thiên các"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo","soHuu":["Ông lão cầm hồ lô vỏ vàng"],"trangThai":"dang-co","blurb":"Chí bảo Bổ Thiên các do Tế Linh kết ra, nuốt hết bão táp hủy diệt vùng núi.","detail":"Hồ lô màu vàng óng toả ra hi quang, trên thân chỉ có một Phù Văn giống khai thiên lập địa khiến vạn linh run rẩy, có khí Hỗn Độn bao phủ. Từ hư không xuất hiện, nuốt hết bão táp mãnh liệt đủ hủy diệt một vùng núi như cá voi hút nước, rồi thu nhỏ bằng lòng bàn tay. Là chí bảo của Bổ Thiên các do Tế Linh (một giàn dây hồ lô) kết ra.","nguon":["@c0109"]},{"id":"ho-lo-vo-xanh","name":"Hồ lô vỏ xanh","cn":"","aliases":["Trái hồ lô màu xanh"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tế Linh"],"trangThai":"dang-co","blurb":"Trái hồ lô màu xanh trên giàn dây hồ lô khô vàng của Tế Linh; khi bị tiếp cận phát khí Hỗn Độn.","detail":"Nằm trên giàn dây hồ lô khô vàng ở Thượng Cổ Tịnh Thổ. Khi Thạch Hạo vọt lên định chạm để đánh thức Tế Linh, hồ lô phát ra khí Hỗn Độn, đạo âm chấn động, hiển hóa Phù Văn ngàn tia vạn sợi, khí thế như thời chưa khai thiên lập địa, đẩy lui nó.","nguon":["@c0111"]},{"id":"co-kiem-thuong-co","name":"Cổ kiếm Thượng Cổ","cn":"","aliases":["Cổ kiếm cắm trên đầu ông lão"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tử Thần"],"trangThai":"dang-co","blurb":"Thanh cổ kiếm rỉ sét cắm trên đầu ông lão tử khí Thượng Cổ; tỏa sát khí, phát tiếng rung, tràn ra máu đen.","detail":"Kiếm vốn sắc bén nay rỉ sét loang lổ, cắm trên đầu ông lão tóc xám. Khi ông lão đòi trả kiếm, thanh kiếm phát tiếng rung, tràn ra vết máu đen. Thanh kiếm dường như bám theo sinh vật khiến nó muốn đập gãy để thoát.","nguon":["@c0111"]},{"id":"ho-lo-vang-hon-don","name":"Hồ lô vàng óng","cn":"","aliases":["Hồ lô vỏ vàng (Đào Dã)","Hồ lô vàng óng (Đào Dã)","Hồ lô vỏ vàng (chí bảo Bổ Thiên các)"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Ông lão cầm hồ lô vỏ vàng"],"trangThai":"dang-co","blurb":"Cái hồ lô vàng óng ông lão phương xa nâng trên tay, tràn ngập khí Hỗn Độn.","detail":"Cùng lúc có tiếng phá không vang tới, một ông lão xuất hiện từ phương xa, tay nâng một cái hồ lô vàng óng tràn ngập khí Hỗn Độn, gợi lai lịch bất phàm chưa rõ.","nguon":["@c0111","@c0112","@c0109"]},{"id":"co-kiem-cam-dau-tu-than","name":"Cổ kiếm cắm đầu Tử Thần","category":"than-khi","categoryLabel":"Thần khí","soHuu":["Tử Thần"],"trangThai":"dang-co","blurb":"Thanh cổ kiếm đâm xuyên đầu Tử Thần, cực bền không sứt mẻ; là kiếm của đối thủ ngày xưa chứ không phải của Hắn.","detail":"Thanh kiếm đâm xuyên đầu vị thần quái Thượng Cổ, cực kỳ bền chắc; nhóc tỳ dùng đỉnh đồng gõ leng keng đốm lửa tứ tung mà đầu lâu lẫn kiếm đều không sứt mẻ. Đào Dã tiết lộ đây không phải kiếm của Tử Thần mà của đối thủ ngày xưa; kiếm thật của Tử Thần rơi mất ở Bách Đoạn sơn mạch.","nguon":["@c0112"]},{"id":"nguyen-thuy-bao-cot","name":"Nguyên Thủy Bảo Cốt","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Bổ Thiên các"],"trangThai":"dang-co","blurb":"Bảo vật đặt trong đại điện nghị sự Bổ Thiên các, Phù Văn lưu chuyển gia trì bắn ra từng tia thần hi.","detail":"Đặt trong đại điện nghị sự của Bổ Thiên các trên ngọn núi cao khảm kỳ thạch phát sáng; Phù Văn lưu chuyển gia trì, bắn ra từng tia thần hi, nơi bàn sự kiện trọng đại như nhiệm vụ Bách Đoạn sơn.","nguon":["@c0112"]},{"id":"bat-lao-than-tuyen","name":"Bất Lão thần tuyền","category":"khac","categoryLabel":"Kỳ vật","soHuu":[],"trangThai":"dang-co","blurb":"Suối thần nằm nơi bí mật trong Bách Đoạn sơn, mục tiêu nhiệm vụ của nhóc tỳ.","detail":"Thần tuyền nằm nơi bí mật trong Bách Đoạn sơn, điều kiện tới gần vô cùng tồi tệ; muốn đến gần phải phá Phù Văn của Thượng Cổ Thánh trận. Bốn lão tiền bối Bổ Thiên các giao Thạch Hạo tìm mang về, ai lập được công sẽ được khắc tên lên Bất Hủ Thần Bi.","nguon":["@c0113","@c0125"]},{"id":"tuyet-ngoc-sam","name":"Tuyết Ngọc Sâm","category":"dan-duoc","categoryLabel":"Linh dược","soHuu":[],"trangThai":"da-dung","blurb":"Cây nhân sâm trắng như ngọc mọc ở cửa cung điện Bổ Thiên các.","detail":"Linh dược quý mọc ở cửa cung điện Bổ Thiên các. Nhóc tỳ Thạch Hạo trộm gặm ăn rồi khai Đào Dã cho — thực ra nó chỉ hỏi cây củ cải ở vườn rau có ăn được không và Đào Dã gật đầu.","nguon":["@c0113"]},{"id":"bat-hu-than-bi","name":"Bất Hủ Thần Bi","category":"khac","categoryLabel":"Bia thần","soHuu":[],"trangThai":"dang-co","blurb":"Bia của Bổ Thiên các, ai lập công sẽ được khắc tên lên.","detail":"Bia thần của Bổ Thiên các; ai mang được Bất Lão thần tuyền về sẽ được khắc tên lên bia này như một vinh dự.","nguon":["@c0113"]},{"id":"linh-duoc-tang-thanh-phong","name":"Linh Dược (tặng Thanh Phong)","category":"dan-duoc","categoryLabel":"Đan dược","soHuu":["Thanh Phong"],"trangThai":"dang-co","blurb":"Một cây linh dược nguyên vẹn tỏa sáng, quý hơn Dược tán.","detail":"Một cây linh dược nguyên vẹn tỏa sáng, quý hơn Dược tán mà đệ tử thiên tài thường dùng. Nhóc tỳ tặng cho đệ đệ Thanh Phong ở Thiên tài doanh, nói là tiền cược thắng hậu duệ một Thái Cổ di chủng, sau lấy làm vật ván cược khiêu chiến.","nguon":["@c0113"]},{"id":"tang-than","name":"Tang thần","category":"khac","categoryLabel":"Vật theo người","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Thứ mang bên người nhóc tỳ khiến nó buộc phải nghe theo.","detail":"Thứ mang bên người Thạch Hạo mà Đào Dã dọa nếu không đi Bách Đoạn sơn thì Hắn không đáp ứng và nó sớm muộn mất mạng. Danh tính thế lực bí ẩn liên quan chưa lộ.","nguon":["@c0113"]},{"id":"thien-cot","name":"Thiên Cốt","category":"khac","categoryLabel":"Kỳ vật","soHuu":[],"trangThai":"dang-co","blurb":"Xương thần có thể tìm được ở Bách Đoạn sơn.","detail":"Một trong các cơ duyên của Bách Đoạn sơn, xương thần được nêu bên cạnh truyền thừa Chư Thánh và thánh dược.","nguon":["@c0113"]},{"id":"ho-lo-xanh-khai-lo","name":"Hồ lô màu xanh","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Các trưởng lão Bổ Thiên các"],"trangThai":"dang-co","blurb":"Hồ lô màu xanh khai lộ, dựng thành thông đạo xanh cho đoàn người rời Bổ Thiên các.","detail":"Trong một mảnh hào quang, hồ lô màu xanh hiện lên lắc lư không ngừng, dựng thành một con đường màu xanh (thông đạo). Đoàn đệ tử Bổ Thiên các đi vào thông đạo và toàn bộ biến mất khỏi Bổ Thiên các, hướng tới điểm đến bí ẩn.","nguon":["@c0114"]},{"id":"cot-thu-doan-khong-thanh","name":"Cốt Thư (bày bán Đoạn Không thành)","category":"khac","categoryLabel":"Vật phẩm","trangThai":"dang-co","blurb":"Loại sách cốt thư được bày bán trong Đoạn Không thành cùng binh khí, dược thảo, xương thú.","detail":"Trong cửa hàng ở Đoạn Không thành bày bán nhiều vật thiết yếu: xương thú trân quý, dược thảo cao tuổi, binh khí và Cốt Thư.","nguon":["@c0115"]},{"id":"xe-keo-rem-ngoc-thach","name":"Xe kéo rèm ngọc thạch","category":"khac","categoryLabel":"Vật phẩm","trangThai":"dang-co","blurb":"Xe của tiểu Bạch Hổ, rèm ghép từ chuỗi ngọc thạch, do hung thú kéo.","detail":"Xe kéo do phu xe Nhân tộc và hung thú kéo, rèm ghép từ chuỗi ngọc thạch; trong xe là con tiểu Bạch Hổ Thái Cổ dị chủng, hai cô gái hầu hạ cho ăn thịt.","nguon":["@c0115"]},{"id":"dai-hoang-kinh","name":"Đại Hoang kinh","cn":"","category":"khac","categoryLabel":"Sách cổ","phamCap":"","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Sách cổ chuyên giới thiệu các loại sinh linh mà nhóc tỳ từng đọc, có ghi chép về Phì Di.","detail":"Sách chuyên giới thiệu các chủng loại sinh linh trong thiên hạ. Nhờ đọc qua Đại Hoang kinh mà nhóc tỳ nhận ra được các dị chủng như Thái Cổ di chủng Phì Di.","nguon":["@c0116"]},{"id":"bao-tai-bao-boi-nha-bep","name":"Bao tải “bảo bối” (nồi niêu xoong chảo)","category":"khac","categoryLabel":"Khác","phamCap":"Phàm phẩm","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Bao tải to Thạch Hạo khoe là “bảo bối”, thực chất là nồi niêu xoong chảo, gia vị “trưng dụng” cả một nhà bếp môn phái.","detail":"Thạch Hạo vác một bao tải to như chuyển nhà, khoe với đám dị tộc là toàn bảo bối; khi mở ra lộ nồi niêu xoong chảo cùng gia vị — cả một nhà bếp bị dọn sạch, có ghi chú tên môn phái, mang vào Bách Đoạn Sơn để sinh tồn nơi hoang dã.","nguon":["@c0117"]},{"id":"bon-goc-linh-duoc-bach-doan-son","name":"Bốn gốc linh dược (vách núi Bách Đoạn Sơn)","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Linh dược","soHuu":[],"trangThai":"dang-co","blurb":"Bốn gốc linh dược sư tỷ Bổ Thiên các phát hiện trên một vách núi trong tiểu thế giới Bách Đoạn Sơn.","detail":"Sư tỷ trong nhóm Bổ Thiên các phát hiện bốn gốc linh dược mọc trên một vách núi giữa tiểu thế giới linh khí đậm đặc của Bách Đoạn Sơn.","nguon":["@c0117"]},{"id":"xich-lan","name":"Xích Lan","category":"linh-khi","categoryLabel":"Linh dược","phamCap":"","soHuu":["Sinh vật hình người ánh bạc"],"trangThai":"bi-cuop","blurb":"Bốn gốc linh dược mọc dàn hàng trên vách núi bên hồ, hình như lưỡi khoan đỏ như máu, nghi giúp đột phá bình cảnh.","detail":"Linh dược quý hiếm: bốn gốc mọc dàn hàng trên vách núi bên hồ trong tiểu thế giới, hình như lưỡi khoan đỏ như máu, có luân văn màu đỏ máu, nghi giúp đột phá bình cảnh. Bị sinh vật hình người ánh bạc ngắt cả bốn gốc.","nguon":["@c0118"]},{"id":"cot-kinh-toan-nghe","name":"Cốt Kính (bảo cốt Toan Nghê)","aliases":["Bảo kính Toan Nghê","cốt kính trắng"],"category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"chí bảo (luyện từ Bảo Cốt Toan Nghê)","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Gương xương trong suốt như ngọc luyện từ Bảo Cốt Toan Nghê; phản chiếu ánh sáng, mặt ngược khắc Phù Văn thôi thúc tia chớp vàng.","detail":"Cốt Kính là Bảo Cụ Thạch Hạo liều mạng đoạt về, tế luyện từ Bảo Cốt của Toan Nghê — loại Thái Cổ di chủng mạnh nhất. Phản chiếu ánh sáng bạc của đối thủ khiến bả vai thủng hai lỗ máu; mặt ngược khắc Phù Văn thôi thúc hàm nghĩa Toan Nghê phóng tia chớp vàng; còn nâng chân Thạch Hạo khi truy đuổi (tiêu hao Tinh Khí Thần) và đánh đầu lâu đối thủ thành tro.","nguon":["@c0119"]},{"id":"cot-tien-mau-vang","name":"Cốt Tiễn màu vàng","aliases":["Kim Giao tiễn","Long Giao tiễn","Cốt Tiễn vàng kim","Cốt Tiễn mùa vàng"],"category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"chí bảo (cốt bảo)","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Mũi tên xương ghép từ hai mảnh xương vàng, phát tiếng rồng gầm, có miệng núi lửa và dung nham.","detail":"Bảo Cụ thứ ba của Thạch Hạo, tạo thành từ hai mảnh xương màu vàng liên kết với nhau, phát tiếng rồng gầm và xuất hiện miệng núi lửa/dung nham. Bẻ gãy chủy thủ bạc, cắt đứt cánh tay trái rồi cắt cổ sinh linh màu bạc. Cũng do Thạch Hạo liều mạng đoạt về, không phải tộc nhân ban.","nguon":["@c0119","@c0134"]},{"id":"cay-quat-mau-bac","name":"Cây quạt màu bạc","aliases":["bảo phiến bạc","Quạt bạc rách nát"],"category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"Bảo Cụ","soHuu":["Sinh linh màu bạc","Thạch Hạo"],"trangThai":"hong","blurb":"Quạt xương bạc của sinh linh màu bạc, phun ra tạo sóng bạc san bằng núi rừng; bị Thạch Hạo cướp và hủy hơn nửa.","detail":"Bảo phiến bạc phun ra hóa thành, tạo sóng bạc san bằng dãy núi phía sau, uy lực cực lớn. Sau khi giết chủ, Thạch Hạo lấy làm chiến lợi phẩm nhưng nó đã nát hơn nửa, khiến Thạch Hạo bi phẫn tiếc nuối hơn cả bảo bối của mình.","nguon":["@c0119","@c0130"]},{"id":"chuy-thu-mau-bac","name":"Chủy thủ màu bạc","category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"Bảo Cụ","soHuu":["Sinh linh màu bạc"],"trangThai":"hong","blurb":"Dao găm xương bạc mài từ Bảo Cốt, phun ra như đòn thứ ba của sinh linh màu bạc.","detail":"Chủy thủ bạc mài từ Bảo Cốt, được sinh linh màu bạc phun ra như đòn thứ ba, dùng quạt kiềm Cốt Kính; bị Cốt Tiễn vàng xoắn đứt làm hai đoạn.","nguon":["@c0119"]},{"id":"xe-phuong-may-do","name":"Xe phượng mây đỏ","aliases":["xe kéo mây đỏ","xe phượng"],"category":"phap-bao","categoryLabel":"bảo vật","phamCap":"bảo vật","soHuu":["Hỏa Linh Nhi"],"trangThai":"dang-co","blurb":"Xe kéo của con gái nhỏ Nhân Hoàng, lượn lờ mây đỏ, lấp loé hào quang đỏ thẫm, được hơn bốn mươi thiên tài hộ tống.","detail":"Chiếc xe kéo lấp loé hào quang đỏ thẫm, lượn lờ mây đỏ, được hơn bốn mươi thiên tài bảo vệ; Thạch Hạo từng thấy trên đường đi Bổ Thiên các. Là bảo vật của con gái nhỏ Nhân Hoàng.","nguon":["@c0119"]},{"id":"tu-van-tam","name":"Tử Vân Tâm","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":["Thạch Hạo"],"trangThai":"da-dung","blurb":"Trái tim của Tử Vân Điêu, một Thái Cổ di chủng hung mãnh, giống viên bảo thạch màu tím to lớn rực rỡ.","detail":"Vật thể màu tím lớn bằng đầu người, óng ánh như kim cương tím, tỏa tử khí và hương thơm nức; dược hiệu bá đạo, có tác dụng lớn trong đột phá. Nhóc tỳ đổi con Linh Tộc màu bạc để lấy, rồi luyện hóa trong hang cổ để mở Động Thiên thứ bảy.","nguon":["@c0120"]},{"id":"sinh-vat-mau-bac-linh-toc","name":"Sinh linh màu bạc (Linh Tộc)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":[],"trangThai":"bi-cuop","blurb":"Con Linh Tộc toàn thân màu bạc có Vương huyết truyền thừa, Thái Cổ di chủng cực hiếm.","detail":"Con Linh Tộc toàn thân màu bạc, có Vương huyết truyền thừa; đồn có linh huyết hiếm do linh tính ngưng tụ (không phải huyết mạch), rèn ra được thì giúp người ngộ đạo. Bị nhóc tỳ chém giết rồi đem trao đổi lấy Tử Vân Tâm.","nguon":["@c0120"]},{"id":"dinh-ngoc-hinh-vuong","name":"Đỉnh ngọc hình vuông","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Đỉnh ngọc dài một thước dùng đựng Tử Vân Tâm.","detail":"Đỉnh ngọc hình vuông dài một thước người áo đen dùng đựng Tử Vân Tâm, mở ra thấy vật thể màu tím, tử khí lưu chuyển. Nhóc tỳ kiểm tra kỹ rồi cất giữ.","nguon":["@c0120"]},{"id":"chuoi-niem-chau-vang","name":"Chuỗi niệm châu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo Cụ","soHuu":["Sư Tử chín đầu"],"trangThai":"dang-co","blurb":"Bảo Cụ của Hoàng Kim sư tử, như chế từ vàng ròng, hào quang trấn áp, được phun ra để chống lại Cốt Tiễn của Nhóc tỳ.","detail":"Chuỗi niệm châu màu vàng như chế từ vàng ròng, tỏa hào quang trấn áp. Khi bị Cốt Tiễn của Nhóc tỳ làm trọng thương, Hoàng Kim sư tử phun ra chuỗi niệm châu này để chống đỡ, hai bảo vật va chạm dữ dội.","nguon":["@c0122"]},{"id":"cot-tien-long-giao","name":"Cốt Tiễn màu vàng (Long Giao tiễn)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Vượt xa cấp bậc bản thân","soHuu":["Nhóc tỳ"],"trangThai":"Nhóc tỳ đang sử dụng","blurb":"Tiễn xương màu vàng của nhóc tỳ, hóa hai giao long chém rụng đầu lâu Sư Tử chín đầu.","detail":"Cốt Tiễn màu vàng, còn gọi là Long Giao tiễn, là tiễn xương của nhóc tỳ. Khi xuất trận khẽ kêu “keng”, hóa thành hai giao long chém rụng bốn đầu lâu Sư Tử chín đầu (hai đầu bên trái rồi hai đầu bên phải). Uy lực vượt xa cấp bậc bản thân Sư Tử chín đầu, khiến sinh linh huyết thống cao quý này không thể lấy bảo thuật cứng rắn mà chống đỡ.","nguon":["@c0123"]},{"id":"chin-rang-nanh-niem-chau-su-tu","name":"Chín răng nanh vàng + niệm châu (bảo cụ Sư Tử chín đầu)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Vượt cấp bậc bản thân","soHuu":["Sư Tử chín đầu (Hoàng Kim sư tử)"],"trangThai":"Sư Tử chín đầu thu về bỏ trốn","blurb":"Bảo cụ của Sư Tử chín đầu: chín răng nanh vàng hóa phi kiếm và chín hạt niệm châu như thế giới nhỏ.","detail":"Bảo cụ của Sư Tử chín đầu (Hoàng Kim sư tử): chín thanh răng nanh màu vàng có thể hóa thành phi kiếm bổ vào đối thủ, cùng chuỗi niệm châu chín hạt — mỗi hạt lóng lánh như một thế giới nhỏ, sương mù lượn quanh, trấn áp đối thủ như đối kháng cả một mảnh thế giới. Cả hai đều vượt cấp bậc bản thân nó. Khi bại trận Sư Tử thu bảo cụ bỏ trốn; nhóc tỳ đuổi theo đòi “trả lại bảo cụ”.","nguon":["@c0123"]},{"id":"bao-duoc-dau-su-tu","name":"Bảo dược đầu sư tử (Huyết dược đầu sư tử)","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Lò bảo dược chứa thần tính","soHuu":["Nhóc tỳ","Bổ Thiên các"],"trangThai":"Đã hầm và ăn hết","blurb":"Bốn đầu lâu Sư Tử chín đầu hầm với bốn cây linh dược thành lò bảo dược chứa thần tính.","detail":"Bốn đầu lâu Sư Tử chín đầu (nơi chứa thần tính, tinh khí thần, sức mạnh màu vàng cực lớn) được nhóc tỳ hầm trong đỉnh đồng bên bờ sông một canh giờ, thêm bốn cây linh dược hái bên hồ để dược tính mạnh thêm. Kết quả là một lò bảo dược khó có thể tưởng tượng. Ăn vào thất khiếu phát sáng, cảm giác phun ra lửa. Nhóc tỳ ăn hết hai đầu cùng hơn nửa đỉnh chất lỏng; năm thiên tài Bổ Thiên các ăn nửa cái đầu lâu, vận Phù Văn tu hành và lần lượt đột phá sau nửa đêm.","nguon":["@c0123"]},{"id":"trung-vang-lang-than","name":"Trứng vàng (nghi hậu duệ Lang Thần)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Nghi hậu duệ Lang Thần","soHuu":["Hỏa Linh Nhi (đoạt được)","Nhóc tỳ (cướp lấy)"],"trangThai":"Bị nhóc tỳ cướp mang đi","blurb":"Quả trứng vàng to bằng chậu nước, khớp chữ khắc vách tường, nghi là hậu duệ của Lang Thần.","detail":"Quả trứng vàng to bằng chậu nước, tỏa ánh sáng, khớp với chữ khắc trên vách tường Ma Quật về hậu duệ Lang Thần. Hỏa Linh Nhi đoạt được từ trong Ma Quật; khi túi da của người đội nón lá vỡ, trứng rơi ra, các thế lực (Sư Tử chín đầu, Ngân Huyết, Vũ Vương, Hỏa Linh Nhi cùng thiên tài Nhân tộc) đều tranh cướp. Nhóc tỳ vọt tới ôm chặt, đòi luộc ăn rồi xông qua bầy sói biến mất.","nguon":["@c0123"]},{"id":"dau-lau-vang-than-tinh","name":"Đầu lâu màu vàng (thần tính)","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Bao hàm lực lượng thần tính","soHuu":["Sư Tử chín đầu (nguồn gốc)"],"trangThai":"Đã hầm làm bảo dược","blurb":"Đầu lâu Sư Tử chín đầu thực chất là chất lỏng đậm đặc và thịt màu vàng bao hàm lực lượng thần tính.","detail":"Đầu lâu màu vàng của Sư Tử chín đầu không có xương thật, gồm chất lỏng đậm đặc và thịt màu vàng thơm nức, bao hàm lực lượng thần tính. Là nguyên liệu để hầm thành lò bảo dược; ăn vào giúp đột phá cảnh giới.","nguon":["@c0123"]},{"id":"trung-than-mau-vang","name":"Trứng thần màu vàng","category":"nguyen-lieu","categoryLabel":"Trứng thần linh","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"da-dung","blurb":"Trứng to như chậu nước, như đúc bằng vàng ròng, vỏ có hoa văn kỳ dị lưu động ánh sáng, cuối cùng nở ra một thần linh non.","detail":"Quả trứng nhóc tỳ cướp được, to như chậu nước, tỏa sóng năng lượng thần bí, nghi là hậu duệ Thần linh. Vỏ cứng nhưng bị đục bằng đá nhọn; dưới tác động lửa và Bảo Thuật khi nhóc tỳ dùng nó làm lá chắn, vỏ trứng vỡ vụn, một sinh vật nhỏ cuộn tròn trong lòng bàn tay nhóc tỳ — thực sự ấp ra một thần linh non.","nguon":["@c0124"]},{"id":"trai-tim-hung-thu-huyet-nhuc-bao-duoc","name":"Trái tim hung thú (huyết nhục bảo dược)","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Bảo dược","soHuu":["Hỏa Linh Nhi"],"trangThai":"da-dung","blurb":"Trái tim hung thú đựng trong đỉnh ngọc, tinh hoa thần tính của hung vật cực mạnh.","detail":"Nơi ngưng kết tinh hoa thần tính của hung vật cực mạnh, đựng trong đỉnh ngọc; Hỏa Linh Nhi lấy ra cho sói con Ấu Thần ăn sạch.","nguon":["@c0125"]},{"id":"chuoi-niem-chau-vang-su-tu","name":"Chuỗi niệm châu vàng (cốt châu Sư Tử)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Sư Tử chín đầu"],"trangThai":"dang-co","blurb":"Cốt châu Hoàng kim do Cửu Linh Vương ban cho Sư Tử chín đầu, mỗi hạt như một thế giới nhỏ, mang quy tắc Phù Văn của dòng tộc.","detail":"Chuỗi niệm châu chế từ Hoàng kim di cốt của tiền bối bộ tộc Sư Tử chín đầu, mỗi hạt như một thế giới nhỏ chứa quy tắc Phù Văn dòng tộc; do Cửu Linh Vương ban cho. Khi phá trận, Sư Tử phun ra để đánh tan thạch lâm.","nguon":["@c0126"]},{"id":"cửu-chuyen-linh-dan","name":"Cửu Chuyển Linh Đan","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Đan cần sáu giọt bảo huyết Thái Cổ di chủng mạnh nhất để luyện chế.","detail":"Linh đan cao cấp cần sáu giọt bảo huyết Thái Cổ di chủng mạnh nhất để luyện; là lý do nhiều thế lực Nhân tộc muốn bắt Sư Tử chín đầu để lấy bảo huyết.","nguon":["@c0126"]},{"id":"bao-tan-vu-tu-mach","name":"Bảo Tán (dù)","category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"","soHuu":["Vũ Tử Mạch"],"trangThai":"hong","blurb":"Cây dù lớn (Bảo Cụ) của Vũ Tử Mạch dùng che lôi điện, bị Cốt Tiễn cắt đứt rách nát.","detail":"Vũ Tử Mạch lấy cây dù lớn (Bảo Cụ) che lôi điện của nhóc tỳ, nhưng bị Cốt Tiễn vàng cắt đứt, trong nháy mắt rách rưới hoàn toàn.","nguon":["@c0128"]},{"id":"bao-y-long-chim-tim","name":"Bảo Y lông chim màu tím","category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"","soHuu":["Vũ Tử Mạch"],"trangThai":"hong","blurb":"Áo giáp Bảo Cụ bện từ lông chim màu tím của Vũ Tử Mạch, bị bảo kính Toan Nghê đánh nổ tung hóa tro bụi.","detail":"Vũ Tử Mạch triển khai Bảo Y bện từ lông chim màu tím, lấp lánh như ánh bình minh để phòng ngự, nhưng cuối cùng bị bảo kính Toan Nghê đánh nổ tung, áo giáp hóa tro bụi, thân thể lộ ra.","nguon":["@c0128"]},{"id":"quyen-sach-co-nhieu-mau-vu-tu-mach","name":"Quyển sách cổ nhiều màu","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Vũ Tử Mạch"],"trangThai":"hong","blurb":"Quyển sách cổ Phù Văn của Vũ Tử Mạch dùng thi triển Bảo Thuật Thông Linh, bị cối xay bạc phá vỡ.","detail":"Quyển sách cổ nhiều màu chứa Phù Văn của Vũ Tử Mạch, như gánh chịu lực lượng năm tháng nên gần như bất hủ. Khi chủ nhân giận dữ thì lúc sáng lúc tối, trông rất bất ổn; cuối cùng bị cối xay bạc của nhóc tỳ nổ tung phá vỡ, khiến Bảo Thuật Thông Linh mất hiệu lực.","nguon":["@c0128"]},{"id":"ho-lo-mau-xanh-te-linh","name":"Hồ lô màu xanh (Tế Linh)","category":"khac","categoryLabel":"Vật phẩm thần bí","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Trái hồ lô màu xanh nằm dưới lá khô của giàn dây hồ lô Tế Linh, mang Phù Văn cổ và khí Hỗn Độn bao phủ.","detail":"Nằm dưới đám lá khô của giàn dây hồ lô Tế Linh trong khu vườn cổ, kích thước tương đương trái hồ lô vàng óng của vị lão tiền bối Bổ Thiên các. Trên hồ lô có Phù Văn cổ lấp loé, khí Hỗn Độn lượn lờ bao phủ như một thế giới mơ hồ trấn áp lại. Cả nhóc tỳ lẫn Bóng Lông đều muốn hái nhưng bản năng ngăn cản.","nguon":["@c0110"],"aliases":["Hồ lô vỏ xanh (Tế Linh)"]},{"id":"ho-lo-vo-xanh-te-linh","name":"Hồ lô vỏ xanh","aliases":["Trái hồ lô màu xanh"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tế Linh"],"trangThai":"dang-co","blurb":"Trái hồ lô vỏ xanh trên giàn dây hồ lô khô vàng của Tế Linh; khi bị tiếp cận phát khí Hỗn Độn hiển hóa Phù Văn đẩy lui.","detail":"Nằm trên giàn dây hồ lô khô vàng ở Thượng Cổ Tịnh Thổ. Khi Thạch Hạo định chạm vào để đánh thức Tế Linh, hồ lô phát ra khí Hỗn Độn, đạo âm chấn động, hiển hóa Phù Văn ngàn tia vạn sợi, khí thế như thời chưa khai thiên lập địa, đẩy lui nó.","nguon":["@c0111"]},{"id":"ho-lo-mau-xanh-khai-thong-dao","name":"Hồ lô màu xanh (khai thông đạo)","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":[],"trangThai":"dang-co","blurb":"Hồ lô màu xanh hiện lên trong hào quang, lắc lư không ngừng, dựng thành một con đường màu xanh làm thông đạo.","detail":"Trong một tiếng “Ầm”, nơi ở của Tế Linh xuất hiện mảnh hào quang; một cái hồ lô màu xanh hiện lên lắc lư không ngừng, dựng thành con đường màu xanh để đoàn người đi vào thông đạo và toàn bộ biến mất khỏi Bổ Thiên các.","nguon":["@c0114"]},{"id":"manh-xuong-thai-co-di-chung","name":"Mảnh xương Thái cổ di chủng","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","soHuu":[],"trangThai":"dang-co","blurb":"Những mảnh xương của Thái cổ di chủng được các trưởng lão thu lại tại nơi ở của Tế Linh.","detail":"Đoàn người tiến vào nơi ở của Tế Linh, các trưởng lão yên lặng cầu khẩn rồi thu lại những mảnh xương của Thái cổ di chủng gần giàn dây hồ lô.","nguon":["@c0114"]},{"id":"tang-than-vat-theo-nguoi","name":"Tang thần","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Thứ mang bên người nhóc tỳ khiến nó buộc phải nghe theo, nếu không đi sẽ mất mạng.","detail":"Vật/thứ theo bên người Thạch Hạo, gắn với thế lực bí ẩn “Hắn”; Đào Dã dọa nếu không vào Bách Đoạn sơn thì “Hắn” không đáp ứng, nó sớm muộn mất mạng. Danh tính và công năng đầy đủ chưa rõ.","nguon":["@c0113"]},{"id":"khay-bac-than-nguyet","name":"Khay bạc","aliases":["Khay bạc như Thần Nguyệt"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Khay bạc thánh khiết nhóc tỳ triệu ra sau lưng để chắn nham thạch và lửa.","detail":"Ánh bạc như nước hóa thành khay bạc cao gần bằng người hiện ra sau lưng nhóc tỳ, thánh khiết như Thần Nguyệt; bất luận nham thạch nóng chảy hay lửa cháy đều bị nó ngăn lại khi Hỏa Vân Tước trút mưa Hỏa văn.","nguon":["@c0118"]},{"id":"huyet-nhuc-bao-duoc-hoa-van-tuoc","name":"Huyết nhục bảo dược (thịt Hỏa Vân Tước)","aliases":[],"category":"dan-duoc","categoryLabel":"Bảo dược","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"da-dung","blurb":"Hơn hai mươi cân thịt Hỏa Vân Tước, ăn vào tăng tinh khí, giúp tiến tới đột phá.","detail":"Thịt tươi thơm sáng óng ánh nhóc tỳ chém rụng được từ Hỏa Vân Tước; nấu chín ăn vào thân thể phát tia sáng, sức mạnh tinh thuần lan khắp thân, tăng tinh khí. Nhóc tỳ tin nếu ngày nào cũng ăn loại huyết nhục bảo dược này chẳng bao lâu sẽ đột phá.","nguon":["@c0118"]},{"id":"tui-da-dung-trung-vang","name":"Túi bằng da thú (đựng trứng vàng)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Người đội nón lá"],"trangThai":"Bị phá nát","blurb":"Túi da thú người đội nón lá dùng đựng quả trứng vàng nghi hậu duệ Lang Thần, phát ra ánh sáng.","detail":"Túi làm bằng da thú, được người đội nón lá mang theo để đựng quả trứng vàng to bằng chậu nước. Túi phát ra ánh sáng khi chứa trứng. Khi người đội nón lá bị thương trong lúc tranh cướp, túi da vỡ ra khiến quả trứng vàng rơi xuống, dẫn tới màn tranh đoạt và việc nhóc tỳ ôm trứng bỏ chạy.","nguon":["@c0123"]},{"id":"quat-bac-rach-nat","name":"Quạt bạc rách nát","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo Cụ (phù cốt nguyên thủy)","soHuu":["Thạch Hạo"],"trangThai":"hong","blurb":"Cây quạt phù cốt nguyên thủy ngân quang lấy từ cường giả Linh Tộc, được tinh khí và sấm chớp nuôi dưỡng.","detail":"Cây quạt rách nát ngân quang mà Thạch Hạo lấy từ cường giả Linh Tộc, từng bị Cốt Tiễn màu vàng cắt nát. Khi bị bốn đại cường giả Vũ tộc vây, Thạch Hạo vận bảo kính Toan Nghê truyền lực sấm sét vào khiến quạt thức tỉnh rồi ném ra nổ tung đánh về bốn người, phế bỏ luôn cây quạt.","nguon":["@c0130"]},{"id":"hac-sat-lien-thanh-duoc","name":"Hắc Sát Liên (Thánh Dược)","cn":"","category":"dan-duoc","categoryLabel":"Linh dược / Thánh Dược","phamCap":"Thánh Dược","soHuu":["Bổ Thiên Các"],"trangThai":"Đã bị đào cả gốc lẫn ngọn, chỉ còn cái hố","blurb":"Cây thuốc quý bậc Thánh Dược của Bổ Thiên Các, sinh trưởng 800 năm, sắp lột xác khi tròn 1000 tuổi.","detail":"Hắc Sát Liên là Thánh Dược trục sự kiện của Bổ Thiên Các, đã sinh trưởng 800 năm và sắp lột xác khi tròn 1000 tuổi. Là loại Thánh Dược cực hiếm ở Đại Hoang — vật có thể làm người chết sống lại — nên khiến các tiền bối những thế lực khiếp sợ khi biết Bổ Thiên Các gây trồng được. Cây thuốc được canh giữ bởi Hắc Hổ Sát trong một hố đất. Khi Trác Vân trưởng lão dẫn đoàn tới giới thiệu thì phát hiện Hắc Sát Liên đã bị kẻ khác đào cả gốc lẫn ngọn, chỉ còn trơ lại cái hố, khiến ông từ ung dung chuyển sang nổi điên gào giận.","nguon":["@c0104"]},{"id":"cot-tien-vang-kim-te-linh","name":"Cốt Tiễn vàng kim","cn":"","category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"Bảo Cụ","soHuu":["Nhóc tỳ"],"trangThai":"Nhóc tỳ đoạt từ tay Tế Linh Xuyên Sơn Giáp, đang sử dụng","blurb":"Bảo Cụ kim cốt kinh người, phát dị tượng núi thây biển máu, từng gây hạo kiếp đồ sát vô số bộ lạc.","detail":"Cốt Tiễn màu vàng kim, một Bảo Cụ có uy lực vượt xa tưởng tượng: khi thi triển phát ra dị tượng núi thây biển máu, tương truyền từng gây hạo kiếp đồ sát vô số bộ lạc. Nhóc tỳ đoạt được từ tay Tế Linh Xuyên Sơn Giáp vàng kim, nghi là bảo vật do tổ tiên truyền lại. Trong trận tranh đoạt Ấu Thần, Cốt Tiễn vọt tới không những đánh gãy hung đao (cốt đao) của Vũ Vương mà còn chặt đứt một cánh tay của Vũ Vương, máu phun tung tóe, khiến đám truy đuổi biến sắc rút lui.","nguon":["@c0125"]},{"id":"dinh-ngoc-trai-tim-hung-thu","name":"Đỉnh ngọc chứa trái tim hung thú","cn":"","category":"dan-duoc","categoryLabel":"Huyết nhục bảo dược","phamCap":"Huyết nhục bảo dược","soHuu":["Hỏa Linh Nhi"],"trangThai":"Hỏa Linh Nhi lấy ra cho sói con (Ấu Thần) ăn","blurb":"Trái tim của một hung vật cực mạnh ngưng kết tinh hoa thần tính, đựng trong đỉnh ngọc, là huyết nhục bảo dược.","detail":"Một chiếc đỉnh ngọc chứa trái tim hung thú — trái tim của một hung vật cực mạnh, ngưng kết tinh hoa thần tính, được xem là huyết nhục bảo dược quý giá. Hỏa Linh Nhi lấy từ trong túi ra, cùng hai cây Linh dược, đưa cho sói con (Ấu Thần) ăn để nuôi dưỡng nó trưởng thành. Sói con ăn sạch.","nguon":["@c0125"]},{"id":"bat-lao-than-tuyen-di-bao","name":"Bất Lão Thần Tuyền","cn":"","category":"khac","categoryLabel":"Thần tuyền / dị bảo","phamCap":"Dị bảo","soHuu":[],"trangThai":"Mục tiêu tìm kiếm; nhóc tỳ ép Sư Tử chín đầu giúp tìm","blurb":"Thần tuyền dị bảo được cho là có thể trị lành thương tổn, kể cả mấy cái đầu bị mất của Sư Tử chín đầu.","detail":"Bất Lão Thần Tuyền là một dị bảo dạng thần tuyền mà nhóc tỳ đòi tìm trong Tiểu Thế Giới. Nhóc tỳ nói nếu tìm được thì có thể trị tốt được cho mấy cái đầu bị mất của Sư Tử chín đầu, nên ép sư tử chở đi tìm và phát thệ hỗ trợ. Gắn với cơ duyên chữa lành trong Tiểu Thế Giới.","nguon":["@c0125"]},{"id":"te-linh-tang-da-ky-la","name":"Tế Linh (tảng đá kỳ lạ)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":[],"trangThai":"Được mang tới sơn môn Bổ Thiên các làm bằng chứng truy nã","blurb":"Tảng đá được nghi là Tế Linh, mang tới trên da thú cổ, hai mặt hiện chữ khiêu khích do Nhóc siêu quậy để lại.","detail":"Một tảng đá kỳ lạ được nghi là Tế Linh, được da thú cổ lấp lánh phù văn chở tới sơn môn Bổ Thiên các cùng cường giả. Mặt trước tảng đá hiện chữ 「Anh Minh Thần Vũ, Quang Minh Chính Đại」, mặt sau hiện 「Nắm Búa Nơi Tay, Ta Có Thiên Hạ」 — dấu vết do Nhóc siêu quậy để lại. Khi được đưa lên cho ba ngàn tân đệ tử xem, dòng chữ khiến mọi người kinh hô nhận ra tên nhóc siêu quậy khét tiếng, trở thành bằng chứng để Hùng Phi trưởng lão phát lệnh truy nã.","nguon":["@c0106"]},{"id":"van-tu-hoan-cot","name":"Văn tự Hoàn Cốt","cn":"","category":"khac","categoryLabel":"Văn tự nhập môn","phamCap":"","soHuu":[],"trangThai":"Được hai trưởng lão giảng cho tân đệ tử Bổ Thiên các","blurb":"Loại văn tự nhập môn mà hai vị trưởng lão giảng giải cho tân đệ tử rồi vội rời đi.","detail":"Văn tự Hoàn Cốt là thứ Hùng Phi và Trác Vân giảng giải cho trăm tân đệ tử tại khu núi đá của Bổ Thiên các. Trong mấy ngày liền, hai vị trưởng lão chỉ gặp mặt một lần, giảng giải văn tự Hoàn Cốt rồi vội vã rời đi, không ở lại lâu.","nguon":["@c0106"]},{"id":"cot-tien-mau-vang-vu-tu-mach","name":"Cốt Tiễn màu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nhóc tỳ"],"trangThai":"Đang dùng","blurb":"Mũi tên cốt màu vàng uy lực mạnh của nhóc tỳ, cắt đứt cây Bảo Tán và hủy một Bảo Cụ của chính nhóc tỳ.","detail":"Cốt Tiễn màu vàng là pháp bảo dạng mũi tên do nhóc tỳ bắn ra trong trận chiến với Vũ Tử Mạch. Uy lực mạnh mẽ: nó cắt đứt cây Bảo Tán (dù) của Vũ Tử Mạch trong nháy mắt khiến cây dù rách rưới, đồng thời cùng tia chớp vàng đánh vào người nàng khiến nàng ho ra máu. Trong quá trình giao chiến, Cốt Tiễn cũng hủy một Bảo Cụ của chính nhóc tỳ, khiến nó đau lòng.","nguon":["@c0128"]},{"id":"bao-tan-du-vu-tu-mach","name":"Bảo Tán (dù)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo Cụ","soHuu":["Vũ Tử Mạch"],"trangThai":"Bị hủy","blurb":"Cây dù lớn (Bảo Cụ) của Vũ Tử Mạch dùng che lôi điện, bị Cốt Tiễn cắt đứt rách nát.","detail":"Bảo Tán là một Bảo Cụ hình dù/ô lớn của Vũ Tử Mạch, được nàng lấy ra để che chắn lôi điện của nhóc tỳ. Tuy nhiên nó bị Cốt Tiễn màu vàng của nhóc tỳ cắt đứt, trong nháy mắt rách rách rưới rưới, hư hại hoàn toàn.","nguon":["@c0128"]},{"id":"chin-rang-nanh-vang-su-tu","name":"Chín răng nanh màu vàng","cn":"","category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"Bảo Cụ","soHuu":["Sư Tử chín đầu"],"trangThai":"Đang sử dụng","blurb":"Sư Tử chín đầu phun ra chín răng nanh màu vàng để tấn công cường giả phía Tây.","detail":"Bảo cụ vũ khí của Sư Tử chín đầu (Hoàng Kim sư tử). Trong lúc bị bốn Người phong ấn Vũ tộc vây bắt, Sư Tử chín đầu phun ra chín răng nanh màu vàng đánh về phía cường giả trấn giữ phương Tây, dùng làm đòn công kích trong cuộc huyết chiến bỏ chạy.","nguon":["@c0129"]},{"id":"buc-tranh-nhan-dien-nhoc-ty","name":"Bức tranh (nhận diện nhóc tỳ)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Sinh vật hình người ánh bạc"],"trangThai":"Do kẻ ánh bạc nắm giữ","blurb":"Bức tranh kẻ ánh bạc dùng để đối chiếu, nhận diện đúng nhóc tỳ là mục tiêu cần truy tìm.","detail":"Một bức tranh mà sinh vật hình người ánh bạc mang theo, dùng để đối chiếu nhận diện nhóc tỳ. Sau khi xem tranh, hắn xác nhận nhắm đúng mục tiêu rồi mới ra tay chiêu dụ. Việc dùng tranh truy tìm gợi mở nhóc tỳ là đối tượng bị nhiều thế lực (Hoàng Kim sư tử chín đầu, kẻ ánh bạc) tranh đoạt.","nguon":["@c0118"]},{"id":"chi-ton-cot","name":"Chí Tôn Cốt","cn":"","category":"khac","categoryLabel":"Bảo vật (cốt)","phamCap":"","soHuu":["Nhóc tỳ"],"trangThai":"Đã mất","blurb":"Bảo vật nhóc tỳ từng sở hữu nhưng đã mất; dẫu mất nó vẫn quật khởi được, chứng minh thiên tư đáng sợ.","detail":"Chí Tôn Cốt là bảo vật mà nhóc tỳ (con Thạch Tử Lăng) từng sở hữu rồi bị mất. Trong mắt bốn cường giả Vũ tộc, việc nhóc tỳ đánh mất Chí Tôn Cốt mà vẫn có thể quật khởi chính là bằng chứng cho thiên tư kinh khủng của nó — đúng nỗi lo của một nguyên lão trong tộc, khiến bọn Thạch Nghị quyết diệt trừ nhân tố bất định này.","nguon":["@c0130"]},{"id":"thai-nhat-chan-thuy","name":"Thái Nhất Chân Thủy","aliases":["Thái Nhất Thần Thủy","Thái Nhất Chân thủy","thủy bảo"],"category":"khac","categoryLabel":"Thần dịch","phamCap":"Thần dịch trân quý","soHuu":[],"trangThai":"dang-co","blurb":"Thần dịch cực kỳ trân quý, một giọt có giá trị liên thành, ẩn chứa Thủy chi pháp tắc; mục tiêu tranh đoạt của Vũ tộc.","detail":"Loại thần dịch có nhiều công hiệu: luyện thành tuyệt thế bảo đan, thêm một giọt tăng phẩm chất Bảo Cụ một đoạn lớn, ẩn chứa Thủy chi pháp tắc, hỗ trợ tu hành làm chơi ăn thật. Chư Thần khi luyện bảo cũng dùng nó để tẩm bổ linh tính cho Bảo Cụ; một giọt giá trị liên thành, trân quý không cách nào tưởng tượng. Vũ tộc cảm ứng khí tức từ mấy trăm năm trước, ra quân ồ ạt và tìm được một ao thần dịch trong sa mạc; hồ này xuất hiện ảo cảnh vừa lừa dối vừa kêu gọi người tiến gần. Với Vũ tộc, thủy bảo có thể khiến tộc quật khởi và xuất hiện một vị Nhân Hoàng.","nguon":["@c0131"]},{"id":"trung-toa-son-dieu","name":"Trứng Tọa Sơn Điêu","aliases":[],"category":"dan-duoc","categoryLabel":"Đại bổ dược","phamCap":"Thánh Phẩm","soHuu":["Thạch Hạo","Đại Hồng Điểu"],"trangThai":"da-dung","blurb":"Đại bổ dược Thánh Phẩm, ba quả trứng to như cối đá, vỏ đen óng như Mặc Ngọc, giàu tinh khí thần.","detail":"Ba quả trứng lớn của Tọa Sơn Điêu, vỏ đen óng như Mặc Ngọc, bên trong ẩn tinh khí nội hàm Phù Văn, giàu tinh khí thần, dùng chữa thương và tẩm bổ. Đại Hồng Điểu cắt trứng bằng lông vũ, phun lửa nướng chín; Thạch Hạo ăn cả ba quả (nặng hơn cả trọng lượng cơ thể) để luyện hóa chữa lành toàn bộ vết thương, Đại Hồng Điểu chỉ ăn được một quả.","nguon":["@c0131"]},{"id":"ngan-lu-thao","name":"Ngân Lũ Thảo","aliases":[],"category":"nguyen-lieu","categoryLabel":"Linh thảo","phamCap":"Chưa rõ","soHuu":[],"trangThai":"dang-co","blurb":"Loại linh thảo mềm mại ấm áp được Tọa Sơn Điêu lót trong tổ chim.","detail":"Loại thảo mềm mại ấm áp mà Tọa Sơn Điêu lót trong tổ chim khổng lồ để ấp trứng.","nguon":["@c0131"]},{"id":"long-than-tieu-hong-dieu","name":"Lông thần Tiểu Hồng Điểu","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Chí Tôn (thần uy)","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Cái lông chim đỏ tươi như máu đựng trong hộp đá, tỏa xích hà và thần uy Chí Tôn.","detail":"Lông chim đỏ tươi như máu, tỏa xích hà và hỏa quang đặc biệt, mang thần uy Chí Tôn khiến Đại Hồng Điểu (cũng là loài chim) run sợ khuất phục, lật mặt quỳ xin làm đồ đệ.","nguon":["@c0132"]},{"id":"sa-mac-ngan","name":"Sa Mạc Ngân","category":"dan-duoc","categoryLabel":"Bảo dược","phamCap":"Bảo dược truyền thuyết","soHuu":["Tiêu Thiên"],"trangThai":"da-dung","blurb":"Bảo dược trong truyền thuyết hơn xa linh dược bình thường, là đóa hoa trắng bạc trên cây xương rồng.","detail":"Đóa hoa trắng bạc đong đưa trên cây xương rồng giữa sa mạc, hương thơm nức, ánh bạc rơi vãi như mưa ánh sáng; do bò cạp bạc khổng lồ canh giữ. Tiêu Thiên hái được và luyện hóa để đột phá Động Thiên thứ tám.","nguon":["@c0132"]},{"id":"hop-da","name":"Hộp đá","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Hộp đá Thạch Hạo dùng để cất giữ lông thần Tiểu Hồng Điểu.","detail":"Hộp đá chứa cái lông thần đỏ tươi của Tiểu Hồng Điểu, Thạch Hạo mở ra để tỏa thần uy khuất phục Đại Hồng Điểu.","nguon":["@c0132"]},{"id":"nuoc-hoang-tuyen","name":"Nước Hoàng Tuyền","category":"khac","categoryLabel":"Bảo dịch","phamCap":"Không rõ","soHuu":["Vũ Văn Thành","Vũ Côn"],"trangThai":"dang-co","blurb":"Bảo dịch trong bảo bình của Vũ tộc, luyện từ phù cốt, phù văn và nước Âm Hà; tỏa ô quang đen phá hủy hài cốt phù văn.","detail":"Ba người Vũ tộc mở bảo bình nước Hoàng Tuyền, tế bảo thuật biến ô quang màu đen thành sinh linh (quỷ quái, Li Long, hình người) phá vỡ toàn bộ hài cốt do Thái Nhất Chân Thủy triệu hoán. Luyện từ phù cốt, phù văn, nước Âm Hà lấy từ mộ phần; vốn định dùng để thâm nhập Tử Vong cấm địa nên không muốn tiêu hao hết.","nguon":["@c0133"]},{"id":"tui-can-khon-phong-che","name":"Túi càn khôn phỏng chế","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Phỏng chế","soHuu":["Vũ Côn"],"trangThai":"hong","blurb":"Bảo cụ thu nạp Vũ Côn tế ra từ tấm da thú, phù văn vô tận; là hàng phỏng chế của túi càn khôn chính phẩm Thượng Cổ.","detail":"Vũ Côn tế ra túi càn khôn phỏng chế từ tấm da thú để thu linh đằng thủ hộ, nhưng túi bị đâm vỡ tan. Tiêu Thiên giải thích túi càn khôn Thượng Cổ chính phẩm luyện từ da Thái Cổ hung thú thiên giai, không gì không thể thu vào; đồ này chỉ là hàng phỏng chế.","nguon":["@c0133"]},{"id":"di-vat-vu-than","name":"Di vật Vũ thần","category":"khac","categoryLabel":"Chứng vật","phamCap":"Không rõ","soHuu":["Vũ Văn Thành"],"trangThai":"dang-co","blurb":"Di vật của Vũ thần (nghiên mực đã dùng hết, chặn giấy) có hào quang thần thánh nhưng không phù văn, dùng chứng minh Vũ tộc là hậu duệ Vũ thần.","detail":"Vũ tộc dùng di vật Vũ thần — nghiên mực đã dùng hết, chặn giấy... tỏa hào quang thần thánh, không có phù văn — để chứng thực là hậu duệ Vũ thần, khiến Thái Nhất Chân Thủy nguyện đi theo Vũ tộc để có cơ hội phong thần.","nguon":["@c0133"]},{"id":"dinh-ngoc-vu-toc","name":"Đỉnh ngọc Vũ tộc","aliases":["Bảo Cụ đỉnh ngọc"],"category":"phap-bao","categoryLabel":"Bảo cụ chứa đựng","phamCap":"Không rõ","soHuu":["Vũ Văn Thành"],"trangThai":"dang-co","blurb":"Đỉnh ngọc Vũ tộc dùng để thu chứa Thái Nhất Chân Thủy; bên trong có nước, bị Nhóc Tỳ nhào vào nuốt sạch.","detail":"Vũ tộc mời Thái Nhất Chân Thủy hóa ánh sáng tiến vào đỉnh ngọc, một giọt không thiếu, mơ tưởng lập quốc; nhưng Nhóc Tỳ nhào vào Bảo Cụ đỉnh ngọc quẫy nước rầm rầm và nuốt từng ngụm lớn Thái Nhất Chân Thủy.","nguon":["@c0133"]},{"id":"quy-thuan-mai-rua","name":"Quy thuẫn mai rùa","category":"phap-bao","categoryLabel":"Khiên / Bảo cụ","phamCap":"Không rõ","soHuu":["Tiêu Thiên"],"trangThai":"hong","blurb":"Tấm khiên Tiêu Thiên tế ra là mai rùa tỏa sáng xanh biếc lóe vô số phú văn áo nghĩa; làm bàn đạp cho Nhóc Tỳ rồi vỡ vụn.","detail":"Tiêu Thiên xuất ra quy thuẫn — mai rùa xanh biếc lóe phú văn áo nghĩa — làm bàn đạp cho Nhóc Tỳ bật xông vào đỉnh ngọc. Do sức bật kinh khủng của Nhóc Tỳ, quy thuẫn rạn nứt rồi vỡ vụn hoàn toàn, đẩy Tiêu Thiên văng ra năm sáu dặm.","nguon":["@c0133"]},{"id":"dinh-quang-chau","name":"Định Quang Châu","cn":"","category":"phap-bao","categoryLabel":"Dị bảo","phamCap":"Không rõ","soHuu":["Tiêu Thiên","Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Mảnh vỡ của Định Quang Châu thời thượng cổ đánh bóng mà thành, tạo màn sáng hình cầu trói chặt và ngăn phù văn.","detail":"Dị bảo do Tiêu Thiên mang tới, vốn là mảnh vỡ của Định Quang Châu thời thượng cổ. Nhóc Tỳ quát “Định!” lấy ra tạo màn sáng hình cầu ngăn công kích phù văn của Vũ tộc và tạm giữ Thái Nhất Chân Thủy. Do đã hư hại nên chỉ phát huy một phần uy lực, màn sáng mờ dần rồi sắp hết tác dụng; cuối cùng được bỏ vào bình ngọc cùng nước thần.","nguon":["@c0134"]},{"id":"binh-ngoc-nuoc-than","name":"Bình ngọc","cn":"","category":"khac","categoryLabel":"Vật chứa","phamCap":"Không rõ","soHuu":["Tiêu Thiên"],"trangThai":"dang-co","blurb":"Bình ngọc Nhóc Tỳ đổ đầy Thái Nhất Chân Thủy và bỏ Định Quang Châu vào, cuối cùng Tiêu Thiên ôm giữ.","detail":"Nhóc Tỳ vội đổ đầy nước thần vào bình ngọc rồi bỏ Định Quang Châu vào trong; sau khi chạy thoát, Tiêu Thiên ôm giữ bình ngọc, kích động vì đã lấy được phần nước thần.","nguon":["@c0134"]},{"id":"noi-den-dai-hong-dieu","name":"Nồi đen của Đại Hồng Điểu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Đại Hồng Điểu"],"trangThai":"dang-co","blurb":"Nồi đen thực chất là một quả trứng chim mài giũa thành, dùng để hấp thu và phong ấn Thái Nhất Chân Thủy.","detail":"Màu đen bóng như mặc ngọc, phù văn chằng chịt, lôi điện tia lửa phong tỏa. Đại Hồng Điểu phun ra để hấp thu, trấn áp và phong ấn Thái Nhất Chân Thủy vào trong.","nguon":["@c0135"]},{"id":"bao-kinh-toan-nghe","name":"Bảo kính Toan Nghê","aliases":["bảo cốt Toan Nghê"],"category":"than-khi","categoryLabel":"Thần khí","phamCap":"Chí bảo","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Chí bảo lấy từ trên người Thái Cổ di chủng, tỏa tia sấm sét dương cương màu vàng thô to, hơn xa bảo cụ thông thường.","detail":"Thạch Hạo dùng bảo kính Toan Nghê áp chế và phá nứt sừng thú đen tà khí của Vũ Văn Thiên.","nguon":["@c0137"]},{"id":"sung-thu-den","name":"Sừng thú đen","aliases":["bảo cụ tà khí"],"category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Vũ Văn Thiên"],"trangThai":"hong","blurb":"Bảo cụ tà khí Vũ Văn Thiên phun ra, phát thần âm điếc tai như muốn đoạn hồn phách.","detail":"Bị bảo kính Toan Nghê phá nứt rồi Cốt Tiễn màu vàng cắt đứt đôi rơi xuống đất.","nguon":["@c0137"]},{"id":"linh-vu-vu-van-thien","name":"Linh Vũ","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Vũ Văn Thiên"],"trangThai":"hong","blurb":"Chiếc lông đuôi chim màu tím Vũ Văn Thiên ngồi lên để bay lên trời.","detail":"Vũ Văn Thiên ngồi trên Linh Vũ định bay vút lên thì bị Cốt Tiễn màu vàng kẹp đứt đôi, suýt mất mạng.","nguon":["@c0137"]},{"id":"tam-da-giao-thu","name":"Tấm da giao thú","aliases":["phù cốt nguyên thủy"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo cụ hiếm","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Tấm da thú của con giao, dung hợp vào thân người thành vuốt giao phá núi vỡ đá. Nhóc Tỳ đoạt được từ thiếu niên cầm đầu Võ Vương phủ.","detail":"Bảo cụ rất hiếm, chỉ người thân phận không bình thường mới có; khi hợp vào thân hóa thành vuốt giao thô to chi chít vảy, phá núi vỡ đá. Thiếu niên cầm đầu Võ Vương phủ dùng nó tấn công Nhóc Tỳ nhưng bị đoạt mất.","nguon":["@c0138"]},{"id":"bao-phien-nam-mau","name":"Bảo Phiến năm màu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Chim Loan năm màu"],"trangThai":"dang-co","blurb":"Bảo phiến năm màu chim Loan phun ra, tạo thành từ cánh chim, đánh xuống tạo hố lớn.","detail":"Chim Loan năm màu phun ra Bảo Phiến năm màu tạo thành từ cánh chim; khi đánh xuống tạo thành hố lớn. Là pháp bảo phòng-công của hậu duệ Thần điểu trong trận chiến với Nhóc Tỳ.","nguon":["@c0140"]},{"id":"phi-kiem-rang-nanh-do-tham","name":"Phi kiếm răng nanh đỏ thẫm","cn":"","aliases":["Phi kiếm mày đỏ thẫm","phi kiếm đỏ thẫm","phù cốt của Phì Di","Phi kiếm răng nanh"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nhóc Tỳ"],"trangThai":"bi-cuop","blurb":"Phù cốt mạnh nhất của Phì Di, tế luyện mấy năm chuyển hóa thành phi kiếm; dài bằng lòng bàn tay, tạo từ răng nanh đánh bóng như mã não đỏ, linh tính mạnh phát ánh lửa đốt cháy.","detail":"Phi kiếm răng nanh đỏ thẫm được Phì Di phun từ miệng, dài bằng lòng bàn tay, tạo từ răng nanh đánh bóng như mã não đỏ, linh tính mạnh và phát ánh lửa đốt cháy. Là phù cốt mạnh nhất của Phì Di, tế luyện mấy năm chuyển hóa thành phi kiếm; bị Nhóc Tỳ nhắm đoạt (cố ý không dùng Cốt Tiễn để giữ nguyên bảo cụ), rơi vào tay Nhóc Tỳ.","nguon":["@c0140"]},{"id":"giao-long-tien","name":"Long Giao tiễn","cn":"","aliases":["Giao Long tiễn"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Tiễn pháp bảo của Nhóc Tỳ, vệt ánh sáng suýt cắt đôi đối thủ khiến máu chảy đầm đìa.","detail":"Nhóc Tỳ phát động Long Giao tiễn, vệt ánh sáng suýt cắt đôi Phì Di khiến máu chảy đầm đìa, mở đường cho đòn bảo kính sấm sét đánh gục đối thủ.","nguon":["@c0140"]},{"id":"suc-dia-phu","name":"Súc Địa phù","cn":"","category":"phap-bao","categoryLabel":"Thần phù","phamCap":"Thần phù thời Thượng Cổ","soHuu":["Người mặc áo bào xanh"],"trangThai":"Số lần dùng có hạn","blurb":"Thần phù thời Thượng Cổ, dán dưới lòng bàn chân hóa thành lưu quang di chuyển tức thời.","detail":"Súc Địa phù là sản phẩm thời Thượng Cổ, giá trị liên thành. Khi dán dưới lòng bàn chân, người dùng hóa thành lưu quang di chuyển tức thời trong nháy mắt, thoát khỏi vòng vây. Người mặc áo bào xanh dùng nó để trốn thoát sau khi bị Nhóc Tỳ cùng đoàn Thái Cổ di chủng đánh trọng thương trong phế tích Bách Đoạn sơn. Nhược điểm là số lần sử dụng có hạn, dùng hết thì không còn tác dụng.","nguon":["@c0142"]},{"id":"cot-kiem-ao-bao-xanh","name":"Cốt kiếm áo bào xanh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Người mặc áo bào xanh"],"trangThai":"Rạn nứt","blurb":"Bảo cốt óng ánh của Người phong ấn, ánh kiếm như ngân hà cắt đôi tảng đá mười mấy vạn cân.","detail":"Cốt kiếm là bảo cốt óng ánh, ánh kiếm rực rỡ tựa ngân hà, uy lực cực lớn — một nhát chém đôi tảng đá nặng mười mấy vạn cân. Người mặc áo bào xanh dùng nó chém lén Nhóc Tỳ. Khi bị Nhóc Tỳ và đoàn Thái Cổ di chủng quần công, cốt kiếm bị rạn nứt.","nguon":["@c0142"]},{"id":"cot-thap-trang-toat","name":"Cốt tháp trắng toát","cn":"","category":"than-khi","categoryLabel":"Dị bảo","phamCap":"Cốt tháp thần thánh","soHuu":[],"trangThai":"Chưa thu phục — bị tranh đoạt","blurb":"Tháp xương trắng toát lơ lửng trong sơn cốc, hào quang lượn lờ, khí lành mù mịt, tỏa hàng vạn tia Thánh quang.","detail":"Cốt tháp trắng toát là dị bảo thần thánh lơ lửng trong sơn cốc giữa phế tích Thái Cổ, hào quang lượn lờ, khí lành mù mịt. Khi bị Nhóc Tỳ dùng bảo kính Toan Nghê chiếu tới rồi lấy Cốt Tiễn màu vàng trấn áp để giam cầm, cốt tháp bùng phát hàng vạn tia Thánh quang. Đây là mục tiêu tranh đoạt của cả Nhóc Tỳ lẫn phe Bạch Hổ; cuộc giành giật còn bỏ ngỏ khi Bạch Hổ kéo tới chặn ngang.","nguon":["@c0142"]},{"id":"xe-keo-bao-cu","name":"Xe kéo bảo cụ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo cụ mạnh","soHuu":["Bạch Hổ"],"trangThai":"Đang sử dụng","blurb":"Xe do bốn cường giả khiêng chở Bạch Hổ, thực chất là một bảo cụ mạnh phát sáng phù văn.","detail":"Chiếc xe kéo do bốn cường giả khiêng, chở con Bạch Hổ Nhân tộc cùng hai thiếu nữ thiên tài và một ông lão cảnh giới. Thực chất đây là một bảo cụ mạnh: khi vận hành phát ra phù văn bao phủ cả sơn cốc, dùng để công kích khiến vách tường đổ nát. Bạch Hổ dùng nó kéo tới nơi cốt tháp trắng toát để tranh đoạt.","nguon":["@c0142"]},{"id":"tui-can-khon-da-thu","name":"Túi Càn Khôn (túi da thú)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Lão già (phe Bạch Hổ)"],"trangThai":"Thuộc phe Bạch Hổ","blurb":"Túi da thú làm từ da quý của Thái Cổ di chủng, miệng túi có sức hút vô cùng, chứa được vạn vật không kể nặng nhẹ.","detail":"Túi Càn Khôn được Bạch Hổ ban cho lão già thuộc phe mình, chế tác từ da quý của Thái Cổ di chủng. Hai thiếu nữ thiên tài Nhân tộc, bốn đại hán và lão già hợp lực tế luyện túi này; miệng túi tỏa hào quang, sinh ra sức hút vô cùng mạnh, hút cả tảng đá mười mấy vạn cân, có thể chứa được vạn vật không kể nặng nhẹ. Nhóc Tỳ vô cùng thèm muốn báu vật này, muốn đoạt lấy để nhốt các Thái Cổ di chủng vào bên trong.","nguon":["@c0143"]},{"id":"tieu-thap-trang-cot-thap","name":"Tiểu tháp trắng (Cốt tháp)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Nghi pháp khí Thượng Cổ chư thánh","soHuu":["Nhóc Tỳ"],"trangThai":"Nhóc Tỳ quấn lên tóc, chưa cảm ứng được","blurb":"Tòa cốt tháp trắng tinh uy lực khủng bố; sau khi tự tế luyện trong Địa Hoàng Hỏa thì co lại thành tiểu tháp cao không tới một tấc, trắng như Dương Chi bạch ngọc.","detail":"Ban đầu là tòa cốt tháp trắng tinh lơ lửng trong khe núi rồi trong dung nham, chỉ chấn động nhẹ đã bốc khí lành đẩy lui cốt tiễn và bảo kính. Bị Nhóc Tỳ và Bạch Hổ quấy nhiễu nhiều lần, cốt tháp thức tỉnh (bảo cụ thành tinh), bùng nổ ánh sáng như sao băng hủy diệt cả vùng núi, bắn xuyên vai Bạch Hổ và xuyên ngực lão già. Uy lực vượt xa chí bảo trấn tộc của Côn tộc; lão già nghi nó là pháp khí Thượng Cổ chư thánh, ngay Nhân Hoàng thấy cũng phải thèm. Cốt tháp tự lao vào biển lửa Địa Hoàng Hỏa để tế luyện/lột xác, hút sạch địa hỏa, cuối cùng co lại thành tiểu tháp cao không tới một tấc, to bằng đốt ngón tay, trắng như Dương Chi bạch ngọc, không phản ứng với phù văn hay thần lực. Nhóc Tỳ đành quấn nó lên sợi tóc xem như đồ trang sức.","nguon":["@c0143"]},{"id":"phi-kiem-may-do-tham-phi-di","name":"Phi kiếm mày đỏ thẫm (của Phì Di)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Phì Di","Nhóc Tỳ"],"trangThai":"Nhóc Tỳ đang dùng","blurb":"Thanh phi kiếm mày đỏ thẫm của Phì Di, hóa thành dải lụa đỏ, Nhóc Tỳ dùng để cắt chém nham thạch đào tìm cốt tháp.","detail":"Phi kiếm mày đỏ thẫm vốn của Phì Di, khi thi triển hóa thành dải lụa đỏ thẫm. Nhóc Tỳ dùng thanh phi kiếm này cắt chém nham thạch, đào tìm cốt tháp trong lòng đất sau khi dung nham đọng lại.","nguon":["@c0143"]},{"id":"canh-kim-o","name":"Cánh Kim Ô","aliases":["Bảo phiến vàng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo cụ Thượng Cổ","soHuu":["Chim thần màu vàng"],"trangThai":"mat","blurb":"Bảo cụ Thượng Cổ hình đôi cánh màu vàng, tạo ánh lửa ngập trời và dung nham.","detail":"Đôi cánh màu vàng lơ lửng, xuất thế tại Phân Bảo Nhai tạo ánh lửa và dung nham cuồn cuộn khiến các sinh linh hỗn chiến tranh đoạt. Là bảo phiến màu vàng, tự chọn chủ mới; bị con chim thần màu vàng cướp được bay đi.","nguon":["@c0144","@c0150"]},{"id":"phap-truong-do-nhu-mau","name":"Pháp trượng đỏ như máu","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo Thượng Cổ","soHuu":["Tất Phương"],"trangThai":"dang-co","blurb":"Pháp trượng đỏ như máu dài không tới một thước, phù văn phát tiếng sấm nổ.","detail":"Rực rỡ óng ánh đỏ như máu, dài không tới một thước, phù văn lượn quanh phát ra tiếng sấm nổ; đã hư hại nứt vỡ chỉ còn một đoạn nhỏ, nếu ôn dưỡng tế luyện lại có thể thành chí bảo trấn giáo. Lộ ra từ tảng đá phát sáng, bị Tất Phương nhanh tay thu được.","nguon":["@c0144"]},{"id":"chien-mau-luc-mau","name":"Chiến mâu (lục mâu)","category":"phap-bao","categoryLabel":"Binh khí","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Rễ cây kỳ lạ hóa lục mâu màu xanh lục, sắc bén xuyên sắt đá.","detail":"Rễ cây thực vật kỳ lạ hóa thành lục mâu màu xanh lục, cứng rắn sắc bén xuyên sắt đá, có phù văn nhưng bị khuyết điểm (phù văn ẩn bên trong). Nhóc Tỳ đoạt lấy định tặng cho Đại Tráng, Bì Hầu ở Thạch thôn.","nguon":["@c0144"]},{"id":"kiem-co","name":"Kiếm Cổ","aliases":["Kiếm gãy","kiếm rỉ sét","thanh kiếm gãy"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp khí Thượng Cổ chư thánh","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Đoạn sắt gãy rỉ sét nặng mấy vạn cân, mang đại sát khí là di vật chư thánh Thượng Cổ.","detail":"Đoạn sắt gãy rỉ sét dài hơn một thước, nửa trên đã gãy thất lạc, chuôi mục nát, nhưng nặng mấy vạn cân, mang đại sát khí khủng khiếp là di vật chư thánh; khi rút ra bốc lên hình ảnh thây chất thành núi máu chảy thành sông. Thân kiếm lạnh lẽo có hoa văn mờ mờ, phát ra tiếng “Kiếm của ta…”. Nhóc Tỳ tìm được để gỡ nguyền rủa Bổ Thiên các, vác lên lưng.","nguon":["@c0145"]},{"id":"tieu-thap-tren-toc","name":"Tiểu tháp","aliases":["Tiểu tháp nhỏ bằng đốt ngón tay","cốt tháp","Tiểu tháp dương chi bạch ngọc"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (uy năng lớn)","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Tiểu tháp nhỏ bằng đốt ngón tay đặt trên tóc Nhóc Tỳ, tự động xua tan sát khí.","detail":"Đặt trên sợi tóc Nhóc Tỳ như vật trang trí; khi Kiếm Cổ tuôn sát khí suýt xoắn nát thân nó, tiểu tháp đột nhiên sáng lên xua tan toàn bộ luồng sát khí mà không ai phát giác, cho thấy uy năng lớn tiềm ẩn chưa khai mở.","nguon":["@c0145","@c0150"]},{"id":"hac-sat-chien-truong-co","name":"Hắc sát","cn":"","category":"khac","categoryLabel":"Hiện tượng","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Làn khói đen của chiến trường cổ ăn mòn mọi bảo vật thời Thượng Cổ.","detail":"Bạch Hổ giải thích làn khói đen lượn lờ trên đỉnh Phân Bảo Nhai là hắc sát của chiến trường cổ, ăn mòn mọi bảo vật từ thời Thượng Cổ khiến chúng mục nát dần; nếu Kiếm Cổ còn Linh thì quả là nghịch thiên.","nguon":["@c0145"]},{"id":"cot-hoan-thuong-co","name":"Cốt hoàn Thượng Cổ","cn":"","category":"phap-bao","categoryLabel":"Pháp khí Thượng Cổ","phamCap":"Pháp khí Thượng Cổ","soHuu":["Hỏa Linh Nhi"],"trangThai":"dang-co","blurb":"Vòng bằng xương màu xanh da trời khắc từ bảo cốt động vật, đầy linh tính nhưng thiếu một miếng.","detail":"Chiếc cốt hoàn (vòng bằng xương) màu xanh da trời khắc từ bảo cốt động vật, giống như khắc từ ngọc thạch, đầy linh tính, phù văn phủ kín, phát sáng trấn áp hư không; là pháp khí Thượng Cổ nhưng thiếu một miếng nên không hoàn chỉnh — nếu có thanh không hư hại sẽ thành chí bảo trấn quốc. Hỏa Linh Nhi giành đeo lên cổ tay.","nguon":["@c0146"]},{"id":"chien-mau-28","name":"Chiến mâu (28 thanh)","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Bảo cụ Thái Cổ","soHuu":["Bạch Hổ"],"trangThai":"hong","blurb":"28 thanh chiến mâu trắng bạc do răng nanh Thái Cổ di chủng hóa thành, đè ép trời đất.","detail":"28 thanh chiến mâu trắng bạc bóng loáng do răng nanh Thái Cổ di chủng hóa thành, to như cột chống trời, đầu mâu nhuốm máu, đè ép trời đất; bùng phát phù văn hình thành sát trận vây giết. Bị Kiếm Cổ của Nhóc Tỳ một nhát chém đứt đôi toàn bộ.","nguon":["@c0148"]},{"id":"bao-y-bach-ho","name":"Bảo y Bạch Hổ","cn":"","category":"phap-bao","categoryLabel":"Chiến y","phamCap":"Bảo cụ Thái Cổ","soHuu":["Bạch Hổ"],"trangThai":"hong","blurb":"Chiến y chế từ da tiền bối Thái Cổ di chủng, phòng ngự cực mạnh.","detail":"Chiến y chế từ da tiền bối Thái Cổ di chủng, phòng ngự cực mạnh khó công phá; Long Giao tiễn (Cốt Tiễn màu vàng) phá được tầng ánh sáng bạc tạo khe khiến Bạch Hổ chảy máu, rồi xé bảo y thành từng mảnh.","nguon":["@c0148"]},{"id":"tui-can-khon","name":"Túi Càn Khôn","aliases":["túi da bảo dược Bạch Hổ","túi da thú"],"category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Bảo cụ mạnh nhất của Bạch Hổ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","tenCu":"","blurb":"Túi da thú bảo cụ mạnh nhất của Bạch Hổ, mở miệng hút vạn vật để đoạt binh khí.","detail":"Túi da thú, bảo cụ mạnh nhất của Bạch Hổ, mở miệng túi hút vạn vật để đoạt binh khí đối thủ; bị kiếm khí Kiếm Cổ chặn khí lành. Sau khi Bạch Hổ mất thần lực khống chế, phù văn túi lu mờ ẩn vào trong, bị Nhóc Tỳ chụp đoạt được; Nhóc Tỳ định dùng bắt hết Thái Cổ di chủng trong Bách Đoạn sơn nhét vào.","nguon":["@c0148","@c0152"]},{"id":"bao-an-bach-ho","name":"Bảo ấn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo cụ Thái Cổ","soHuu":["Bạch Hổ"],"trangThai":"hong","blurb":"Bảo cụ Bạch Hổ phun ra từ miệng nện tới, bị kiếm gãy chém nổ tung.","detail":"Bảo cụ Bạch Hổ há miệng phun ra nện tới Nhóc Tỳ, bị Nhóc Tỳ chém Kiếm Cổ làm nổ tung thành một chùm ánh sáng đáng sợ; là một trong các bảo cụ dùng tinh huyết ôn dưỡng tế luyện nhiều năm, nổ tan khiến Bạch Hổ phun máu tươi.","nguon":["@c0148"]},{"id":"kiem-gay-phap-khi-thuong-co","name":"Kiếm gãy (pháp khí Thượng Cổ)","cn":"","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Pháp khí Thượng Cổ","soHuu":["Nhóc Tỳ (Thạch Hạo)"],"trangThai":"Nhóc Tỳ đang sử dụng","blurb":"Thanh kiếm nát rỉ sét của Nhóc Tỳ nhưng uy lực khủng khiếp, càng đánh càng mạnh, khi vệt rỉ sét tróc ra lộ thân kiếm đen thui.","detail":"Kiếm gãy là pháp khí Thượng Cổ trong tay Nhóc Tỳ (Thạch Hạo), thoạt nhìn chỉ là thanh kiếm nát rỉ sét nhưng uy lực khủng khiếp, đối đầu ngang ngửa với Nguyên Từ Phong của Kim Sí Bằng điểu. Càng đánh càng mạnh: vệt rỉ sét tróc ra để lộ thân kiếm đen thui, ánh kiếm mãnh liệt hơn, uy năng cực hạn tăng dần khiến Kim Sí Bằng điểu khiếp sợ do dự. Khi Nhóc Tỳ rót toàn bộ tinh khí thần vào, thanh kiếm gãy như từ trong giấc ngủ ngàn thu tỉnh dậy, biến thành một vầng thái dương chói lọi, phóng thích toàn lực. Nhóc Tỳ một mực bảo lưu thần uy khó lường của kiếm gãy, gợi mở lai lịch phi thường chưa lộ hết.","nguon":["@c0149"]},{"id":"nguyen-tu-phong","name":"Nguyên Từ Phong","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo (tế luyện từ Tế Linh Nguyên Từ Sơn)","soHuu":["Kim Sí Bằng điểu"],"trangThai":"hong","blurb":"Ngọn núi mang từ tính (nam châm) do Kim Sí Bằng điểu phun ra, khắc chế binh khí kim loại, hút chặt binh khí và bảo cụ đối thủ.","detail":"Nguyên Từ Phong (còn gọi Nguyên Tử Phong / Từ Sơn) là bảo cụ của Kim Sí Bằng điểu, hình dạng một hòn đá đầy bụi bẩn phun ra biến thành ngọn núi khổng lồ mang từ tính. Chuyên khắc chế binh khí kim loại, hút chặt và trấn áp kiếm gãy cùng các bảo cụ đối thủ, tia sáng nguyên từ có thể xuyên thủng cường giả; là chí bảo dù không phải pháp khí Thượng Cổ. Bảo cụ này nguyên là một Tế Linh danh chấn đại địa tên Nguyên Từ Sơn, từng bị một con Đại Bằng điểu màu vàng đánh bại rồi tế luyện thành bảo cụ. Sư Tử chín đầu và tộc ba mắt nhận ra lai lịch của nó.","nguon":["@c0149","@c0150"]},{"id":"bao-phien-vang-canh-kim-o","name":"Bảo phiến vàng (cánh Kim Ô)","cn":"","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Pháp khí Thượng Cổ","soHuu":["Kim Sí Bằng điểu"],"trangThai":"Kim Sí Bằng điểu đang sử dụng","blurb":"Cây quạt toàn thân vàng óng lấy cánh Kim Ô tế luyện, có thể biến thành cánh thần vỗ ra thần hỏa; đoạt được trên Phân Bảo Nhai.","detail":"Bảo phiến vàng là pháp khí Thượng Cổ của Kim Sí Bằng điểu, một cây quạt toàn thân vàng óng lấy cánh của Kim Ô tế luyện mà thành, xen lẫn lông chim Kim Ô thuần huyết. Khi tung ra, thần hỏa bộc phát, đại hỏa ngập trời khiến mặt đất hóa thành dung nham. Bảo phiến còn có thể biến thành một chiếc cánh thần to lớn vỗ xuống, mang theo thần hỏa và phù văn đáng sợ. Đây là pháp khí sót lại của Thượng Cổ chư thánh, được Kim Sí Bằng điểu đoạt được trên Phân Bảo Nhai. Nó mạnh hơn cả kiếm gãy nhưng vẫn từng trúng một tia kiếm khí của Nhóc Tỳ. 「Lấy cánh của Kim Ô tế luyện mà thành, bảo cụ thật mạnh mẽ!」","nguon":["@c0149"]},{"id":"hac-oa-noi-den","name":"Hắc Oa","cn":"","aliases":["Nồi đen"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo cụ","soHuu":["Đại Hồng Điểu"],"trangThai":"dang-co","blurb":"Bảo cụ của Đại Hồng Điểu luyện chế từ vỏ trứng, ngậm trong miệng tỏa vạn hào quang cứng rắn đối chọi ác điểu.","detail":"Bảo cụ của Đại Hồng Điểu luyện chế từ vỏ trứng, ngậm trong miệng tỏa vạn hào quang, khí lành, cứng rắn để đối chọi ác điểu; bị Nhóc Tỳ giật lấy nện lên đầu Đại Hồng Điểu. Nghĩa đen là cái nồi đen, nghĩa bóng là bị oan ức.","nguon":["@c0151"]},{"id":"mau-huyet-kim-si-dai-bang","name":"Máu huyết Kim Sí Đại Bằng","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Tinh huyết bảo dược","soHuu":[],"trangThai":"dang-co","blurb":"Máu của chim thần bán huyết, bảo dược hiếm có chứa vô hạn tinh hoa thần thánh, dùng ninh nấu bồi bổ thân thể.","detail":"Máu huyết của Kim Sí Đại Bằng — chim thần bán huyết — là bảo dược hiếm có, giá trị khó tưởng tượng; Người phong ấn khuyên tận dụng, cả đám tìm suối trong lột da rửa thịt ninh nấu di chủng bồi bổ thân thể; Hỏa Linh Nhi biết vài phương thuốc cổ giúp tinh huyết phát huy dược hiệu tốt nhất, dù có thể chọc giận tộc Kim Bằng.","nguon":["@c0151"]},{"id":"canh-ho-cot-bach-ho","name":"Canh hổ cốt Bạch Hổ","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Thực dược","soHuu":["Thạch Hạo"],"trangThai":"da-dung","blurb":"Nấu từ chân sau Bạch Hổ ba canh giờ, nước canh đặc sệt óng ánh, ăn vào cảm giác lỗ chân lông thông thấu.","detail":"Canh nấu từ chân sau Bạch Hổ ba canh giờ, nước canh đặc sệt óng ánh, khi đến gần hiện hư ảnh bạch hổ, ăn vào cảm giác lỗ chân lông thông thấu; Nhóc Tỳ dùng bảo thuật làm tan cả xương thành chất lỏng, cả đám tranh nhau uống. Vài con Tử Điêu, Hỏa Nha uống xong đột phá bình cảnh tăng thêm một tầng.","nguon":["@c0152"]},{"id":"thit-bao-vien","name":"Thịt Bạo Viên","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Huyết nhục bảo dược","soHuu":[],"trangThai":"da-dung","blurb":"Huyết nhục bảo dược tinh khí cường đại, giúp di chủng liền xương, khép vết thương, thuần huyết, đột phá.","detail":"Thịt của Bạo Viên (Cự viên, cổ huyết đậm đặc tỏa hào quang đen) là huyết nhục bảo dược tinh khí cường đại; đám di chủng ăn vào xương gãy liền lại, vết thương khép, Tử Điêu ăn hơn ngàn cân cảm thấy sắp đột phá, Sư Tử chín đầu máu trở nên thuần huyết hơn.","nguon":["@c0152"]},{"id":"cot-dao-xanh-nhat-ngu-lao","name":"Cốt đao màu xanh nhạt","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Vũ khí","soHuu":["Ngũ lão"],"trangThai":"dang-co","blurb":"Cốt đao của Ngũ lão, đao khí phóng hơn mười thước ép cổ thụ cự thạch thành bột.","detail":"Cốt đao màu xanh nhạt của Ngũ lão, đao khí phóng hơn mười thước ép cổ thụ cự thạch thành bột; dùng chống sinh linh ba đầu Linh tộc nhưng bị đánh văng.","nguon":["@c0153"]},{"id":"thong-linh-than-hoa","name":"Thông Linh Thần Hoa","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Thánh dược","soHuu":[],"trangThai":"mat","blurb":"Loại thánh dược trong Thần viên, phấn hoa của nó có thể khiến vật mở linh trí biết nói.","detail":"Thông Linh Thần Hoa là loại thánh dược trong Thần viên (Bách Thảo viên); phấn hoa của nó có thể khiến vật (như tảng đá) dính vào mà mở linh trí biết nói.","nguon":["@c0153","@c0154","@c0158"],"aliases":["Thông Linh Hoa"]},{"id":"linh-huyet-linh-toc","name":"Linh huyết Linh tộc","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Linh huyết","soHuu":[],"trangThai":"dang-co","blurb":"Huyết của cường giả Linh tộc cực quý, có thể giúp ngộ đạo.","detail":"Linh huyết của cường giả Linh tộc cực quý giá, có thể giúp ngộ đạo; cánh tay cụt của sinh linh ba đầu Linh tộc có linh huyết mạnh mẽ, có thể ngưng luyện, giá trị quý hơn linh huyết Linh tộc ánh bạc Nhóc Tỳ từng lấy trước đó.","nguon":["@c0153"]},{"id":"day-leo-tim-thanh-tinh","name":"Dây leo tím thành tinh","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Linh dược","soHuu":[],"trangThai":"hong","blurb":"Linh dược Thần viên thành tinh, dài mười thước như giao long tím, có linh trí, chủ động tấn công người xâm nhập.","detail":"Dây leo tím là linh dược trong Thần viên đã thành tinh sinh ra linh trí, dài mười thước như giao long tím, cắm rễ trong nham thạch, chủ động tấn công người xâm nhập; van xin Nhóc Tỳ tha nhưng vẫn phản kích bằng nhánh khác, bị Nhóc Tỳ giật đứt nhổ tận gốc.","nguon":["@c0153"]},{"id":"da-than-thach","name":"Đả Thần Thạch","cn":"","aliases":["ngoan thạch","hòn đá nhỏ","viên đá thần nhỏ"],"category":"khac","categoryLabel":"Đá kỳ vật","phamCap":"Nghi kỳ vật Thượng Cổ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Tảng đá biết nói cực kỳ cứng rắn, đập một lần trúng một lần, không sứt mẻ dù đập mạnh; sinh linh nghi là Đả Thần Thạch trong truyền thuyết.","detail":"Nhóc Tỳ dùng ngoan thạch làm vũ khí ném đập Hoàng Kim thú, 'đập cái nào trúng cái đó'; dù đập rất mạnh vẫn không hề sứt mẻ, chỉ gào khóc thảm thiết. Có sinh linh nghi đây là Đả Thần Thạch trong truyền thuyết — loại đá vốn chỉ có vài khối, bị Thượng Cổ đại năng lấy đi luyện chí bảo. Danh tính Đả Thần Thạch hiện chỉ là suy đoán của các sinh linh.","nguon":["@c0155","@c0157","@c0159"]},{"id":"bat-lao-tuyen-tuyen-tri","name":"Bất Lão Tuyền (tuyền trì)","cn":"","aliases":["Bất Lão Thần Tuyền","Bất Lão Tuyền Trì","Tuyền trì màu vàng kim"],"category":"khac","categoryLabel":"Thần trì / Kỳ vật","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Ao thần trì rộng một trượng vuông tỏa kim quang rực rỡ như thái dương, mục tiêu tranh đoạt của các sinh linh; nằm trong trường vực kinh khủng.","detail":"Cái ao Bất Lão Tuyền rộng một trượng vuông tỏa quang huy vàng chói mắt như thái dương, khiến đất trời ráng lửa mênh mông. Nhiều sinh linh hình người, chim, thú cố tiến lại gần nhưng bị trường vực cực kỳ kinh khủng cản, còn ở ngoài mấy trượng. Nhóc Tỳ tính chờ thiếu nữ tóc tím lấy được rồi mới ra tay đoạt.","nguon":["@c0155"]},{"id":"tui-da-bao-duoc","name":"Túi da bảo dược","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược / Túi chứa","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Túi da chứa hai ba chục gốc bảo dược, trong đó sáu bảy cây hoàn hảo, Nhóc Tỳ đoạt được từ Hoàng Kim thú.","detail":"Túi da chứa chừng hai ba chục gốc bảo dược, trong đó có sáu bảy cây hoàn hảo không sây sát gì. Nhóc Tỳ tự nhặt lấy sau khi đập ngất Hoàng Kim thú.","nguon":["@c0155"]},{"id":"sung-hoang-kim-thu","name":"Sừng Hoàng Kim thú","cn":"","aliases":["sừng Thần bộc thông linh"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Hai sừng vàng kim ánh vàng xán lạn của Hoàng Kim thú, mài thành bột làm thuốc dẫn hiếm có.","detail":"Hai cái sừng vàng kim của Hoàng Kim thú (Thần bộc thông linh), toả linh khí nồng đậm. Khi mài thành bột dùng làm thuốc dẫn hiếm có. Bị Nhóc Tỳ dùng ngoan thạch đập bẻ đoạt lấy rồi đập ngất chủ nhân sừng.","nguon":["@c0156"]},{"id":"huyet-nhuc-bao-duoc-chu-kien","name":"Huyết nhục bảo dược (của Chư Kiền)","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Bảo dược","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Tảng huyết nhục Thạch Hạo xé được từ tay Chư Kiền, cất vào túi làm bảo dược.","detail":"Tảng huyết nhục bảo dược Thạch Hạo vật lộn xé được từ tay hung thú Chư Kiền, nhét vào túi tuyên bố muốn ăn sạch nó.","nguon":["@c0157"]},{"id":"bat-lao-tuyen-rong-nho","name":"Bất Lão Tuyền (rồng nhỏ)","aliases":["Bất Lão Thần Tuyền","Bất Lão Tuyền Trì"],"category":"khac","categoryLabel":"Bảo vật","phamCap":"Thần vật Thượng Cổ","soHuu":[],"trangThai":"mat","blurb":"Bảo vật ở thần trì đã hóa thành con rồng nhỏ màu vàng dài hơn một thước đang lột xác định hóa hình, nên thần tuyền khô cạn.","detail":"Không còn là chất lỏng vàng kim mà đã hóa thành con rồng nhỏ màu vàng dài hơn một thước đang lột xác định hóa hình, khiến thần tuyền khô cạn chỉ còn bùn cát. Bị Thạch Hạo cắn đứt đuôi, rồng gầm thét phá tung tuyền trì rồi hóa hào quang bỏ chạy; đuôi rồng bị Thạch Hạo giữ lại.","nguon":["@c0157"]},{"id":"bun-cat-than-tri","name":"Bùn cát thần trì","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"da-dung","blurb":"Bùn cát óng ánh ẩm ướt tỏa hào quang vàng kim, phóng thích sức mạnh thần thánh bất hủ, là phần sót lại của Bất Lão Tuyền.","detail":"Bùn cát long lanh ẩm ướt tỏa hào quang vàng kim, nguồn phát ra các sóng sức mạnh thần thánh bất hủ; phần còn sót của Bất Lão Tuyền sau khi khô cạn. Được Ngoan thạch và Thạch Hạo tranh nhau ăn.","nguon":["@c0157"]},{"id":"duoi-rong-nho-bat-lao-tuyen","name":"Đuôi rồng nhỏ","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Đuôi con rồng vàng (Bất Lão Tuyền) bị Thạch Hạo cắn đứt và giữ lại khi rồng bỏ chạy.","detail":"Đuôi con rồng vàng lột xác từ Bất Lão Tuyền, bị Thạch Hạo cắn đứt lìa; cuối cùng Thạch Hạo chụp lấy giành giữ khi rồng hóa hào quang bỏ chạy.","nguon":["@c0157"]},{"id":"binh-ngoc-nhot-rong-bat-lao-tuyen","name":"Bình ngọc nhỏ","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Vật chứa","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Bình ngọc nhỏ Nhóc Tỳ dùng đậy chặt năm con rồng nhỏ Bất Lão Tuyền để không chạy.","detail":"Theo lời ngoan thạch, đậy chặt năm giọt Bất Lão Tuyền hóa thành năm con rồng nhỏ trong bình ngọc thì rồng không chạy được; Nhóc Tỳ nhét năm con rồng vào rồi đậy nắp.","nguon":["@c0158"]},{"id":"cat-than-bun-cat-vang","name":"Cát thần (bùn cát màu vàng)","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Thần tính","soHuu":["Nhóc Tỳ"],"trangThai":"da-dung","blurb":"Cát thần Nhóc Tỳ nhai để luyện hóa nâng thực lực; Đả Thần Thạch nói loại này khó tiêu hóa.","detail":"Bùn cát thần màu vàng có thần tính, Nhóc Tỳ nhai và luyện hóa toàn bộ để mong lớn thêm hai ba tuổi, nâng cao thực lực. Đả Thần Thạch than loại cát này khó tiêu hóa.","nguon":["@c0160"]},{"id":"nam-dong-thien-chim-than","name":"Năm Động Thiên chim thần của Thạch Nghị","category":"khac","categoryLabel":"Khác","phamCap":"Trấn tộc","soHuu":["Thạch Nghị"],"trangThai":"dang-co","blurb":"Năm Động Thiên phát sáng quanh Thạch Nghị, mỗi cái tẩm bổ một sinh linh chí tôn hóa từ mảnh phù văn.","detail":"Quanh người Thạch Nghị hiện ra năm Động Thiên, mỗi Động Thiên tẩm bổ một sinh linh chí tôn Thái Cổ hóa từ một mảnh phù văn: Khổng Tước ngũ sắc, Bệ Ngạn, Kim Sí Đại Bằng (Kim Bằng)... Là dị tượng phù văn biểu hiện bảo thuật luyện đến cảnh giới xuất thần nhập hóa.","nguon":["@c0160"]},{"id":"chi-ton-cot-nhoc-ty","name":"Chí Tôn Cốt (trong ngực Thạch Hạo)","cn":"","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Thần cốt cực phẩm","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Đoạn thần cốt (thụ cốt/xương ức) trong ngực Thạch Hạo; Bảo cốt nguyên bản đã bị cướp cấy vào Thạch Nghị, nay khí tức Chí Tôn Cốt thức tỉnh tái sinh.","detail":"Đoạn xương thần thánh trong ngực Thạch Hạo, mang khí tức Chí Tôn quen thuộc từ bé nó. Bảo cốt nguyên bản của nó đã bị cướp cấy vào thân thiếu niên thần thánh Thạch Nghị khiến Thạch Hạo lưu lạc thân nhân ly biệt. Chương này khí tức Chí Tôn Cốt thức tỉnh, hào quang hóa thành mặt trời nhỏ, bên trong tựa một đứa trẻ lóng lánh ngồi xếp bằng — một vị Chí Tôn được thai nghén; toàn bộ Thái Nhất Chân Thủy và tinh huyết ngưng tụ về ngực nó, mở ra hy vọng tái sinh một Chí Tôn Cốt mới.","nguon":["@c0135"]},{"id":"noi-den-trung-chim-dai-hong-dieu","name":"Nồi đen (trứng chim mài giũa)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Đại Hồng Điểu"],"trangThai":"dang-co","blurb":"Pháp bảo của Đại Hồng Điểu, không phải nồi sắt mà do trứng chim mài thành, dùng hấp thu và phong ấn nước thần.","detail":"Đen bóng như mặc ngọc, phù văn chằng chịt cùng lôi điện tia lửa. Đại Hồng Điểu phun ra để hấp thu Thái Nhất Chân Thủy bị phung phí, nhiều lần nuốt-nhả nước thần.","nguon":["@c0135"]}]};
